/// id is the running processor, now start others
#[allow(unused)]
fn processor_start(id: usize) {
    use crate::processor::processor::PROCESSORS;
    let nums = MAX_PROCESSORS;
    for i in 0..nums {
        if i == id {
            continue;
        }
        Instruction::hart_start(i, 0);
        // info!("[kernel] start to wake up processor {}... ",i);
    }
}

/// the rust entry-point of os
/// return true if need reboot (but not supported yet)
fn main(id: usize, first: bool) -> bool {
    if first {
        info!("id: {id}");
        banner::print_banner();
        processor::processor::init(id);
        // ★ 启动期竞态修复：在 devices::init（其 init_network 会一次性 spawn 所有 per-core
        //   NetIrqTask 并注册 waker）之前，由 BSP 单线程预建全部核的 task_queue，关闭
        //   "副核未 init 时 task_queue=None 被跨核入队"的调度死锁窗口。
        #[cfg(feature = "smp")]
        processor::processor::prebuild_all_task_queues();
        hal::trap::init();
        devices::init();
        // [net_outbound] 在 fs::init 注册 /dev/{u}random 之前,于首个 hart 给 CSPRNG 播种一次。
        //   直接读 Timer::read()(无设备依赖),故放在此处安全;off-build 下此行消失。
        #[cfg(feature = "net_outbound")]
        crate::fs::devfs::urandom::seed_rng_at_boot();
        fs::init();
        // ★ SMP [reclaim]: 初始化 FilePageCache 回收水位线（需在帧分配器 init 后）。仅 SMP。
        #[cfg(feature = "smp")]
        crate::fs::page::reclaim::PAGE_RECLAIM.init_watermarks();
        // [6.4] pstore 初始化：检查上次崩溃记录（在 mm/fs init 后，地址已映射）。仅在 diag 模块存在时编译。
        #[cfg(any(
            feature = "smp",
            feature = "diag",
            feature = "lockdep",
            feature = "heartbeat",
            feature = "framediag",
            feature = "oops"
        ))]
        crate::diag::pstore::init(Constant::MEMORY_END);
        // fs::vfs::file::list_apps();
        // fs::ext4::page_cache_test();
        #[cfg(not(feature = "smp"))]
        executor::init();
        // [netcheck] bring-up 自检构建:用内核内主动 TCP 连公网取代 add_initproc(不起 shell、不需磁盘),
        //   跑完打印 connect/send/recv 并关机。默认(无 netcheck)走正常 add_initproc。
        #[cfg(feature = "netcheck")]
        task::schedule::spawn_kernel_task(crate::diag::netcheck::netcheck_main());
        #[cfg(not(feature = "netcheck"))]
        task::schedule::spawn_kernel_task(
            async move{
                task::add_initproc();
            }
        );

        // [1.4] 异步回写 kthread（仅 SMP，native ext4）：周期把 dirty FilePageCache 页回写磁盘。
        #[cfg(feature = "smp")]
        task::schedule::spawn_kernel_task(crate::fs::page::writeback_loop());

        // [异步控制台] flusher kthread（仅 SMP）：周期把控制台 ring 非阻塞落 UART，然后开启异步路径。
        //   _print 此后仅入 ring 即返回，不再全程关中断逐字符忙等慢 UART（SMP 全核串行拖垮整机的根因）。
        //   panic/shutdown 走同步 + console_flush 兜底，崩溃信息不丢。
        #[cfg(feature = "smp")]
        {
            task::schedule::spawn_kernel_task(async {
                use core::time::Duration;
                loop {
                    let n = hal::console::console_drain();
                    if n == 0 {
                        crate::timer::timed_task::ksleep(Duration::from_millis(2)).await;
                    } else {
                        crate::utils::async_utils::yield_now().await;
                    }
                }
            });
            // net_outbound 下保持同步控制台:git 等用户态程序在网络重负载期间产生大量串口输出,
            //   异步控制台的后台 flush 任务可能被网络任务挤占导致输出滞后/丢行。默认路径保持
            //   原有的异步控制台(console_set_async(true)),字节不变。
            #[cfg(not(feature = "net_outbound"))]
            hal::console::console_set_async(true);
        }

        #[cfg(feature = "smp")]
        processor_start(id);
    } else {
        processor::processor::init(id);
        hal::trap::init();
    }
    // ★ 标记本核已上线：epoch 帧回收求 min 时只统计在线核，避免离线核把 safe 钳在 0
    //   导致帧永不回收（-smp N<4 场景）。仅 SMP 编译（smp 模块单核下不存在）。
    #[cfg(feature = "smp")]
    crate::smp::tlb::mark_hart_online(id);
    info!("[kernel] -------hart {} start-------",id);
    unsafe {
        Instruction::enable_timer_interrupt();
        #[cfg(feature = "smp")]
        {
            // ★ 启用 IPI 接收，以支持跨核通信（TLB 击落、重调度 Resched）。
            Instruction::enable_software_interrupt();
        }
    // ★[借鉴·Chronix] 下 91 行沿用自 Chronix:os/src/main.rs
    }
    timer::set_next_trigger();
    executor::run_until_shutdown();
    // return false: HAL will shutdown
    false
}

fn enable_kvm() {
    KVMSPACE.lock().enable();
}

#[cfg(target_arch="loongarch64")]
fn pre_main(id: usize, first: bool) -> bool {
    if first {
        mm::init();
    } else {
        enable_kvm();
    }
    main(id, first)
}

