//! RyOS 内核全局常量(块大小、页大小、抢占调度节拍、内存布局等)
pub const BLOCK_SIZE: usize = 512;

pub const PAGE_SIZE: usize = 4096;

// ── Preemptive scheduling constants ──
/// Preempt timer tick frequency (Hz).
/// Single-core: 1000Hz — 1ms granularity, low overhead
/// Multi-core:  10000Hz — 100μs granularity, better tail latency
// any(preempt, smp)：task 多核设计下抢占常驻；smp 关时退化为 preempt 条件，单核字节不变。
#[cfg(any(feature = "preempt", feature = "smp"))]
#[allow(dead_code)]
pub const PREEMPT_TICK_HZ: usize = if cfg!(feature = "smp") { 10_000 } else { 1_000 };

/// Default timeslice in microseconds.
/// ★[iozone Min=0 验证] 原值 单核100ms/多核10ms 过大:缓存命中快 IO(读1MB<1ms)远小于时间片→
///   抢占永不触发→worker 一口气霸占 CPU 做完自己全部 IO、并发测量窗口内其他 worker 一次没轮到→
///   Min xfer=0。降到 1ms 让快 IO 也能被周期性抢占、公平轮转。
#[cfg(any(feature = "preempt", feature = "smp"))]
pub const PREEMPT_TIMESLICE_US: u64 = if cfg!(feature = "smp") { 500 } else { 500 };

/// Maximum spins before yielding in wait_unlock (used by FlexGuard in Phase 2)
pub const SPIN_LIMIT: usize = 1000;

/// ★ SMP 自旋退避阈值：自适应自旋锁达到此自旋次数后调用 spin_yield（临时开中断做有用功）。
#[cfg(feature = "smp")]
pub const SPIN_BACKOFF: usize = 40;

//! Kernel panic handling: dump diagnostics then power down.

use core::{arch::asm, panic::PanicInfo};
use hal::addr::VirtAddr;
use hal::instruction::{Instruction, InstructionHal};
use hal::{addr::VirtAddrHal, constant::{Constant, ConstantsHal}, println};
use log::*;

/// Entry invoked on an unrecoverable failure; never returns.
#[panic_handler]
fn panic(info: &PanicInfo) -> ! {
    // ★ SMP: 关异步控制台路径 + 同步全清 ring，保证崩溃信息不丢（非 SMP 下两者为 no-op）。
    // 这里的顺序是硬性要求：先切回同步输出，再把环形缓冲区里残留的字节冲刷干净。
    #[cfg(feature = "smp")]
    {
        hal::console::console_set_async(false);
        hal::console::console_flush();
    }

    hal::util::backtrace();

    // 优先打印精确的源码位置；拿不到位置时退化为仅打印消息。
    match info.location() {
        Some(location) => error!(
            "[kernel] Panicked at {}:{} {}",
            location.file(),
            location.line(),
            info.message()
        ),
        None => error!("[kernel] Panicked: {}", info.message()),
    }

    unsafe { Instruction::shutdown(true) }
}

