/// 为 Arc<Spin> 起一个简短的类型别名。
/// ★ SMP：这里用的是 SpinSmpLock —— 它在自旋等锁的间隙允许临时放开中断去干别的活；
///   而在单核构建中，SpinSmpLock 退化成与 SpinNoIrqLock 等同，编译出来的二进制毫无差别。
pub type Shared<T> = Arc<SpinSmpLock<T>>;

/// 为 Option<Arc<Spin>> 起一个简短的类型别名。
pub type SharedOption<T> = Option<Arc<SpinSmpLock<T>>>;

/// 把给定值包成共享对象返回。
pub fn new_shared<T>(data: T) -> Shared<T> {
    Arc::new(SpinSmpLock::new(data))
}
/// 把给定的可选值包成共享的可选对象返回。
pub fn new_shared_option<T>(data: Option<T>) -> SharedOption<T> {
    if let Some(payload) = data {
        Some(Arc::new(SpinSmpLock::new(payload)))
    } else {
        None
    }
}

/// 表示一个任务（进程或线程）。
pub struct TaskBlock {
    // ! 创建后即固定、不再变动的字段
    /// 本任务的唯一标识
    pub tid: TidHandle,
    /// 指向线程组组长的弱引用
    pub leader: Option<Weak<TaskBlock>>,
    /// 本任务自身是否就是线程组的组长
    pub is_leader: bool,
    // ! 仅在自己的执行上下文里改写，且仅当前任务会去访问
    pub trap_context: UPSafeCell<TrapContext>,
    /// 等待事件时挂起本任务、事件就绪后唤醒它所用的 waker
    pub waker: UPSafeCell<Option<Waker>>,
    /// 保存线程 ID 的那块地址
    pub tid_address: UPSafeCell<TidAddress>,
    /// 记录本任务时间统计的记录器
    pub time_recorder: UPSafeCell<TimeRecorder>,
    /// 本任务涉及的 futex 列表。
    pub robust: UPSafeCell<UserMutPtr<RobustListHead>>,
    // ! 仅本任务自身可写，但允许其他任务读取
    /// 本任务的退出码
    pub exit_code: AtomicUsize,
    /// 本任务运行的那个 ELF 文件
    pub elf: Shared<Option<Arc<dyn File>>>,
    #[allow(unused)]
    /// 用户栈起始地址，建线程时会用到
    pub base_size: AtomicUsize,
    /// 本任务当前所处的状态
    pub task_status: SpinNoIrqLock<RunState>,
    // ! 本任务以及其他任务都可能写入
    /// 本任务的用户态虚拟地址空间
    pub vm_space: UPSafeCell<Shared<UserAddrSpace>>,
    /// 指向父任务
    pub parent: Shared<Option<Weak<TaskBlock>>>,
    /// 所有子任务的集合
    pub children: Shared<BTreeMap<Pid, Arc<TaskBlock>>>,
    /// 本任务的文件描述符表
    pub fd_table: Shared<FdTable>,
    /// 本任务所属的线程组
    pub thread_group: Shared<ThreadSet>,
    /// 所属进程组的 id
    pub pgid: Shared<PGid>,
    /// 通过信号管理器集中处理本任务的全部信号
    pub sig_manager: Shared<SignalState>,
    /// 处理信号期间指向用户上下文 ucontext 的指针。
    pub sig_ucontext_ptr: AtomicUsize,
    /// 当前工作目录所对应的 dentry
    pub cwd: Shared<Arc<dyn Dentry>>,
    /// 本任务的间隔（interval）定时器。
    pub itimers: Shared<[ITimer; 3]>,
    /// 本任务的 posix 定时器集合
    pub posix_timers: Shared<BTreeMap<TimerId, PosixTimer>>,
    pub next_timer_id: AtomicUsize,
    /// [3.4] 虚拟运行时间（依权重累计的运行纳秒数）：local 就绪队列拿它当排序键，从而在每个核上实现按权重的公平调度。
    /// 它取代了 osr 原先使用的 PELT sche_entity；仅在 SMP 构建下生效。
    #[cfg(feature = "smp")]
    pub vruntime: core::sync::atomic::AtomicU64,
    /// [5.x] 所属资源隔离组：任务一律归属某个 cgroup，fork 时从父任务继承 cgroup（含 CPU 加权 vruntime
    /// 与带宽配额）。默认归入 ROOT_CGROUP（不加任何限制，零回归）。仅 SMP 下用（单核无 cgroup 概念，统一等权公平）。
    #[cfg(feature = "smp")]
    pub cgroup: alloc::sync::Arc<crate::cgroup::Cgroup>,
    /// [5.4] 本进程的 PID 名额记在哪个 cgroup 上（= fork 时父任务的 cgroup）。仅 leader（新进程）有值；
    /// 线程与 initproc 为 None（不单独占 PID 名额）。消亡时据此 uncharge_pid，与 try_charge_pid RAII 配对。仅 SMP。
    #[cfg(feature = "smp")]
    pub pid_charged_to: Option<alloc::sync::Arc<crate::cgroup::Cgroup>>,
    /// [5.5] 本任务已向其 cgroup 记账的【缺页 owned 物理页数】（匿名/COW/私有文件写所分配的私有页）。
    /// 缺页时 +1（current_task 计费到 self.cgroup），exec 重建地址空间时归还并清零，TCB Drop 时归还。
    /// 单线程进程精确；多线程共享地址空间时为近似（各线程记各自缺页，线程退出即还，略偏松）。仅 SMP。
    #[cfg(feature = "smp")]
    pub mem_charged: AtomicUsize,
    /// [R7] 实时优先级：取 0 即普通任务，1~99 为实时优先级（数值越高越优先）。调度器凭此辨别 RT 任务。仅 SMP 下使用。
    #[cfg(feature = "smp")]
    pub rt_priority: core::sync::atomic::AtomicU8,
    /// ★ SMP-safe：exec 触发的跨核终止标志。由执行 exec 的那个核负责置位，目标线程则在自己核的 trap 流程中读取它，
    /// 以此避开跨核访问 UPSafeCell 所带来的数据竞争。仅 SMP 下使用。
    #[cfg(feature = "smp")]
    pub pending_exit: AtomicBool,
    /// ★[fork 饿死修复] 新生标志：任务【首次】被调度入队前为 true。fork 出的子任务尚未在任何核跑过、
    /// 无缓存亲和，首次入队应【可被偷】(stealable)，让空闲核兜底捞起，避免被硬钉在繁忙核 local 队列饿死
    /// (iozone-t / lmbench 多进程在忙核上互等的根因)。调度闭包首次取用即清零，此后回归正常(唤醒/让出
    /// 仍按缓存亲和入 non-stealable)，故不动既有 net 等热路径行为。仅 SMP。
    #[cfg(feature = "smp")]
    pub fresh_spawn: AtomicBool,
