/// 全系统任务的统一登记表，负责所有任务的集中管理。
/// ★ 多核优化：内层由互斥锁换成读写自旋锁（SpinSmpRwLock）——查询类（get_task / 计数 /
///   遍历快照）走读锁可多核并行，只有 add/remove 走写锁独占。单核下 SpinSmpRwLock 退化为
///   SpinNoIrqRwLock，与原互斥语义等价、零回归；多核下放宽读并发，缓解高频任务表查询的串行。
pub struct TaskTable (SpinSmpRwLock<BTreeMap<Tid, Arc<TaskBlock>>>);
impl TaskTable {
    /// 构造一个空的 `TaskTable`
    pub fn new() -> Self {
        TaskTable(SpinSmpRwLock::new(BTreeMap::new()))
    }
    /// 把一个任务登记进管理器（写锁）
    pub fn add_task(&self, task: &Arc<TaskBlock>) {
        self.0.wlock().insert(task.tid(), task.clone());
    }
    /// 判断除 initproc 外是否还存在其他任务（读锁）
    pub fn has_task_except_initproc(&self) -> bool {
        let registry = self.0.rlock();
        return registry.len() > 1
    }
    /// 从管理器中注销某个任务（写锁）
    pub fn remove_task(&self, tid: Tid) {
        assert!(tid != INITPROC_PID);
        // ★ [退出争用修复] 把摘下的 Arc 移出锁作用域后再析构。
        //   原写法 `self.0.wlock().remove(&tid);` 中,remove 返回的 Arc 是语句临时量,会在 `;` 处
        //   【先于写锁 guard】析构;若它是最后一个引用,`TaskBlock::drop` → `vm_space` 整体释放
        //   (大量用户帧 + 页表,很重) 就发生在【持有 TASK_MANAGER 全局写锁】期间。并发退出
        //   (iozone -t 收尾多进程同时被 reap)会全序列化在这把锁上 → 实测 10000 自旋争用崩溃、
        //   退出阶段假性"卡死"。改为:内层块取出 Arc 即释放写锁,再于锁外让 Arc 归零析构。
        let removed = { self.0.wlock().remove(&tid) };
        drop(removed);
    }
    /// 依据 tid 查询对应任务（读锁）
    pub fn get_task(&self, tid: Tid) -> Option<Arc<TaskBlock>> {
        if let Some(found) = self.0.rlock().get(&tid) {
            Some(found.clone())
        } else {
            None
        }
    }
    /// 取出 init 任务
    pub fn get_init_proc(&self) -> Arc<TaskBlock> {
        self.get_task(INITPROC_PID).unwrap()
    }
    /// 将 BTreeMap 中的全部任务收集为向量（读锁快照）
    pub fn tasks_group(&self) -> Vec<Arc<TaskBlock>> {
        let registry = self.0.rlock();
        let mut snapshot = Vec::new();
        for entry in registry.values() {
            snapshot.push(entry.clone())
        }
        snapshot
    }
    /// 对每个任务依次执行给定的操作
    pub fn for_each_task<F: FnMut(&Arc<TaskBlock>)>(&self, mut callback: F) {
        self.tasks_group().iter().for_each(|item| callback(item));
    }
}
/// 将拥有相同进程组 id 的任务聚合在一起协同工作。
pub struct PgrpTable (SpinNoIrqLock<BTreeMap<PGid, Vec<Weak<TaskBlock>>>>);

impl PgrpTable {
    /// 构造一个空的 `PgrpTable`
    pub const fn new() -> Self {
        Self(SpinNoIrqLock::new(BTreeMap::new()))
    }
    /// 以组长任务为基础建立一个新进程组
    pub fn add_group(&self, group_leader: &Arc<TaskBlock>) {
        info!("add group with leader {}, now pgid is {}" , group_leader.tid(), group_leader.pgid());
        let leader_pgid = group_leader.tid();
        group_leader.set_pgid(leader_pgid);
        info!("add group with leader {}, now pgid is {}" , group_leader.tid(), group_leader.pgid());
        let mut members = Vec::new();
        members.push(Arc::downgrade(group_leader));
        self.0.lock().insert(leader_pgid, members);
        info!("insert group {} with leader {}" , leader_pgid, group_leader.tid());
    }
    /// 把任务加入指定进程组
    pub fn add_task_to_group(&self,pgid: PGid, task: &Arc<TaskBlock>) {
        task.set_pgid(pgid);
        self.0.lock().get_mut(&pgid).unwrap()
        .push(Arc::downgrade(task));
    }
    /// 依据 pgid 取出整个进程组
    pub fn get_group(&self, pgid: PGid) -> Option<Vec<Weak<TaskBlock>>> {
        self.0.lock().get(&pgid).cloned()
    }
    /// 把任务从其所在进程组里剔除
    pub fn remove(&self, task: &Arc<TaskBlock>) {
        self.0.lock().get_mut(&task.pgid()).unwrap()
        .retain(|member|member.upgrade().map_or(false, |strong| Arc::ptr_eq(task, &strong)));
    }
}
/// 进程组管理器的全局单例
pub static PROCESS_GROUP_MANAGER: PgrpTable = PgrpTable::new();
/// 任务管理器的全局单例
pub static TASK_MANAGER: Lazy<TaskTable> = Lazy::new(TaskTable::new);

