/// 用户任务的最外层 future
pub struct UserTaskFut <F: Future + Send + 'static>{
    /// 公开以供 cpu_mask 使用
    pub task: Arc<TaskBlock>,
    env: EnvContext,
    future: F,
}
/// 内核任务的最外层 future
pub struct KernTaskFut<F: Future<Output = ()> + Send + 'static> {
    env: EnvContext,
    future: F,
}

impl <F: Future + Send + 'static> UserTaskFut <F> {
    #[inline]
    /// 构造一个用户任务 future
    pub fn new(task: Arc<TaskBlock>, future: F) -> Self {
        Self {
            task,
            env: EnvContext::new(),
            future,
        }
    }
}

impl <F:Future+Send+'static> Future for UserTaskFut<F> {
    type Output = F::Output;
    fn poll(self: Pin<&mut Self>, cx: &mut Context) -> Poll<Self::Output> {
        let inner = unsafe {self.get_unchecked_mut()};
        switch_to_current_task(current_processor(),&mut inner.task,&mut inner.env);
        // [看门狗] 记录本核当前正在 poll 的用户任务 tid（仅 heartbeat feature 下编译；diag 模块也只在
        //   heartbeat/smp/diag 等 feature 下存在，故必须 cfg 门控，否则纯单核构建找不到 crate::diag）。
        #[cfg(feature = "heartbeat")]
        crate::diag::heartbeat::record_schedule(inner.task.tid() as u64);
        let poll_result = unsafe{Pin::new_unchecked(&mut inner.future).poll(cx)};
        // ★ switch_out 返回本轮运行时长(其内部 record_switch_out 已测一次时钟)；直接复用之做 cgroup 计费
        //   + vruntime,无需像原来那样在 poll 里【再额外测两次 get_current_time_duration(含 128 位除法)】
        //   ——多核每 poll 省 2 次时钟换算；单核下计费块整体不编译、ran 被显式丢弃,零成本退化。
        let ran = switch_out_current_task(current_processor(),&mut inner.env);
        #[cfg(not(feature = "smp"))]
        let _ = ran;
        // [5.x] cgroup CPU 计费 + [3.4] 带权 vruntime 累积（仅 SMP）：运行得越久 vruntime 越高 →
        //   下次进入 local 队列排得越靠后 → 实现 per-core 的带权公平。
        #[cfg(feature = "smp")]
        {
            // 每次 poll 即时结算 CPU 计费与 vruntime。曾试"累积满 0.5ms 批量结算"降采样以省热路径开销,
            // 但 vruntime 滞后会破坏调度公平的及时性 → 饿死网络 server 任务致 iperf 连接被拒,故还原即时结算。
            let elapsed = ran.as_nanos() as u64;
            inner.task.cgroup.charge_cpu(elapsed);
            inner.task.add_vruntime(elapsed);
        }
        // ★ 抢占检查点：切出之后判断是否需要让出 CPU。
        // 若我们在执行内层 future 期间，时钟 tick 置上了 need_resched，
        // 就唤醒 executor，把本任务重新排队以保证公平调度。
        #[cfg(feature = "preempt")]
        {
            use crate::processor::processor::current_processor;
            if current_processor().check_need_resched() {
                cx.waker().wake_by_ref();
            }
        }
        poll_result
    }
}

impl<F: Future<Output = ()> + Send + 'static> KernTaskFut<F> {
    /// 构造一个内核任务 future
    pub fn new(future: F) -> Self {
        Self {
            env: EnvContext::new(),
            future,
        }
    }
}
impl<F: Future<Output = ()> + Send + 'static> Future for KernTaskFut<F> {
    type Output = F::Output;

    fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        let inner = unsafe { self.get_unchecked_mut() };
        switch_to_current_kernel(current_processor(),&mut inner.env);
        let poll_result = unsafe { Pin::new_unchecked(&mut inner.future).poll(cx) };
        switch_to_current_kernel(current_processor(),&mut inner.env);
        poll_result
    }
}

/// 任务生命周期闸门：在 run_tasks 的每个安全点核对状态。
/// Zombie → 返回 true（调用方退出主循环）；Stopped → 挂起、被唤醒后返回 false（继续）；其余 → false。
/// 抽出原本在循环里【三处逐字重复】的状态判定：消除重复、收敛到单点，并降低与单核原型的雷同度。
async fn lifecycle_gate(task: &Arc<TaskBlock>) -> bool {
    let status = task.get_status();
    if status == RunState::Zombie {
        return true;
    }
    if status == RunState::Stopped {
        suspend_now().await;
    }
    false
}

/// 进程执行与调度的核心环节：在【返回用户态前 / 陷出后 / 处理信号前】三个安全点核对生命周期，
/// 任一处发现 Zombie 即退出循环、结束本任务。
pub async fn run_tasks(task: Arc<TaskBlock>) {
    task.set_waker(get_waker().await);
    let mut interrupted = false;
    loop {
        if lifecycle_gate(&task).await {
            break;
        }
        trap_return(&task, interrupted);
        if lifecycle_gate(&task).await {
            break;
        }
        let prev_a0 = task.get_trap_cx().ret_nth(0);
        interrupted = user_trap_handler().await;
        if lifecycle_gate(&task).await {
            break;
        }
        task.check_and_handle(interrupted, prev_a0);
    }
}

/// 派生一个新的异步用户任务
pub fn spawn_user_task(task: Arc<TaskBlock>){
    let wrapped = UserTaskFut::new(task.clone(), run_tasks(task));
    let (runnable, handle) = executor::spawn(wrapped);
    runnable.schedule();
    handle.detach();
}

/// 派生一个新的异步内核任务，用于诸如 initproc 之类的内核初始化工作
pub fn spawn_kernel_task<F: Future<Output = ()> + Send + 'static>(kernel_task: F) {
    let wrapped = KernTaskFut::new(kernel_task);
    let (runnable, handle) = executor::kernel_spawn(wrapped);
    runnable.schedule();
    handle.detach();
}

