impl dyn Dentry {

    /// 依据给定路径查找目录项：
    /// 先在 dcache 中查询，
    /// 未命中则从当前目录项出发进行搜索；
    /// 只返回 USED 状态的目录项，遇到非法路径会 panic
    pub fn find(self: &Arc<Self>, path: &str) -> Result<Option<Arc<dyn Dentry>>, SysError> {
        // 调用方应传入相对路径，先剥掉开头的 '/'
        let relative = path.trim_start_matches("/");
        let mut node = self.clone();
        if relative.is_empty() {
            return Ok(Some(node));
        }
        log::info!("path {}", relative);

        // 把相对路径里的 '.'/空段丢弃、'..' 就地回退父项，余下的拼回规范化字符串
        let mut kept: Vec<&str> = Vec::new();
        for part in relative.split("/") {
            match part {
                "" | "." => {}
                ".." => node = node.parent().ok_or(SysError::ENOENT)?,
                other => kept.push(other),
            }
        }
        let normalize_path = kept.join("/");
        log::info!("normalize path: {}", normalize_path);

        // 调用其它目录项 trait 方法之前必须先放掉 dcache 读锁，故用裸块界定其作用域
        let cached = {
            let cache = DCACHE.rlock();
            cache.get(&(node.path() + &normalize_path)).cloned()
        };
        if let Some(hit) = cached {
            return Ok(match hit.state() {
                DentryState::NEGATIVE => None,
                _ => Some(hit),
            });
        }

        let resolved = node.clone().walk(relative)?;
        if resolved.state() == DentryState::NEGATIVE {
            info!("[DENTRY] invalid path! {}", resolved.path());
            Ok(None)
        } else {
            Ok(Some(resolved.clone()))
        }
    }

    /// 按给定的相对路径（例如 a/b/c）逐级行走并查找目录项，
    /// 沿途构建目录项树；
    /// 从当前目录项开始递归地往下走，
    /// 一旦找到目标或抵达不存在的路径即返回；
