/// 单核运行队列 —— 按**唤醒来源**分流的双 lane 就绪队列。
///
/// 不采用「单条 VecDeque + 头插/尾插」的写法，而是把就绪任务拆到两条独立 lane：
///   · `woken`        —— 从挂起态被重新唤醒的任务（IO/事件完成，时延敏感）。新唤醒者
///                        压栈到 lane 头部，最先获得 CPU，体现「抢占」意图。
///   · `round_robin`  —— 运行中主动让出（`woken_while_running`）以及内核任务。排到尾部，
///                        先入先出，体现「公平轮转」。
///
/// 取任务时**永远先抽干 `woken` lane**，空了才轮到 `round_robin`，从而让刚就绪的
/// 时延敏感任务优先于轮转队列执行。两条 lane 的入/出规则合起来，与旧式单队列
/// （抢占任务头插、普通任务尾插、统一从头消费）在调度顺序上**完全等价**——
/// 改的只是组织形式，单核下的可观察行为不变。
#[cfg(not(feature = "smp"))]
pub struct RunQueue {
    /// 唤醒优先 lane：LIFO，抢占语义
    woken: SpinNoIrqLock<VecDeque<Runnable>>,
    /// 轮转 lane：FIFO，公平调度
    round_robin: SpinNoIrqLock<VecDeque<Runnable>>,
}
#[allow(dead_code)]
#[cfg(not(feature = "smp"))]
impl RunQueue {
    pub const fn new() -> Self {
        Self {
            woken: SpinNoIrqLock::new(VecDeque::new()),
            round_robin: SpinNoIrqLock::new(VecDeque::new()),
        }
    }

    pub fn init(&self) {
        *self.woken.lock() = VecDeque::new();
        *self.round_robin.lock() = VecDeque::new();
    }

    /// 运行中让出 / 内核任务 —— 进轮转 lane 尾部（公平）。
    pub fn enqueue_round_robin(&self, runnable: Runnable) {
        self.round_robin.lock().push_back(runnable);
    }

    /// 从挂起态被唤醒 —— 进唤醒 lane 头部，最新唤醒者最先跑（抢占）。
    pub fn enqueue_woken(&self, runnable: Runnable) {
        self.woken.lock().push_front(runnable);
    }

    /// 取下一个待运行任务：唤醒 lane 优先，抽干后再取轮转 lane。
    pub fn dequeue(&self) -> Option<Runnable> {
        if let Some(runnable) = self.woken.lock().pop_front() {
            return Some(runnable);
        }
        self.round_robin.lock().pop_front()
    }

    pub fn is_empty(&self) -> bool {
        self.woken.lock().is_empty() && self.round_robin.lock().is_empty()
    }

    pub fn len(&self) -> usize {
        self.woken.lock().len() + self.round_robin.lock().len()
    }
}
