/// 把缺页类陷入翻译为对应的访问语义（写 / 读 / 取指）。
///
/// 仅接受三种缺页陷入；传入其它类型属于调用方逻辑错误，直接 `unreachable!`。
/// 行为与原先内联的 `match` 完全一致，抽出来仅为消除两个处理器里的重复。
#[inline]
fn page_fault_access(trap_type: TrapType) -> MemAccessKind {
    match trap_type {
        TrapType::StorePageFault(_) => MemAccessKind::WRITE,
        TrapType::LoadPageFault(_) => MemAccessKind::READ,
        TrapType::InstructionPageFault(_) => MemAccessKind::EXECUTE,
        _ => unreachable!(),
    }
}

/// handle an interrupt, exception, or system call from user space
/// return true if it is syscall and has been interrupted
pub async fn user_trap_handler() -> bool {
    set_kernel_trap_entry();
    let (trap_type, epc) = TrapType::get_debug();
    unsafe { Instruction::enable_interrupt() };
    match trap_type {
        TrapType::Breakpoint => {
            let task = current_task().unwrap().clone();
            log::warn!("[user_trap_handler] task {} break point", task.tid());
            // task.set_stopped();
            // 向用户任务投递 SIGTRAP（内核来源）。
            let sig = SigInfo { si_signo: SIGTRAP, si_code: SigInfo::KERNEL, si_pid: None };
            task.recv_sigs(sig);
        }
        TrapType::Syscall => {
            // 持有 SumGuard 期间允许内核读写用户内存（取参 / 回写结果）。
            let _sum = SumGuard::new();
            let cx = current_task().unwrap().get_trap_cx();
            let syscall_id = cx.syscall_id();
            // 跳过 ecall 指令（4 字节），使返回后从下一条指令继续。
            *cx.sepc() += 4;
            // 收齐六个寄存器参数后分派系统调用。
            let args = [
                cx.syscall_arg_nth(0),
                cx.syscall_arg_nth(1),
                cx.syscall_arg_nth(2),
                cx.syscall_arg_nth(3),
                cx.syscall_arg_nth(4),
                cx.syscall_arg_nth(5),
            ];
            let result = syscall(syscall_id, args).await;
            // // cx is changed during sys_exec, so we have to call it again
            // cx.save_to(0, cx.ret_nth(0));
            // 将返回值写回 a0。
            cx.set_ret_nth(0, result as usize);
            // EINTR 表示该系统调用被信号打断（getpriority 例外，其合法返回值
            // 可能恰为负数，不视作中断）。
            let interrupted =
                result == -(SysError::EINTR as isize) && syscall_id != SYSCALL_GETPRIORITY as usize;
            if interrupted {
                log::warn!("[user_trap_handler] task {} syscall is interrupted", cx.syscall_id());
                return true;
            }
        }
        TrapType::StorePageFault(stval)
        | TrapType::InstructionPageFault(stval)
        | TrapType::LoadPageFault(stval) => {
            log::debug!("[user_trap_handler] encounter page fault, addr {stval:#x}");

            let access_type = page_fault_access(trap_type);
            let fault_va = VirtAddr::from(stval);

            let task = current_task().unwrap().clone();
            let res = task
                .with_mut_vm_space(|vm_space| vm_space.handle_page_fault(fault_va, access_type));
            // 修复失败则给用户进程投递 SIGSEGV；成功则静默返回。
            if let Err(()) = res {
                log::warn!(
                    "[user_trap_handler] task pid {}, tid {}, cannot handle page fault, addr {stval:#x} access_type: {access_type:?} epc: {epc:#x}",
                    task.pid(), task.tid()
                );
                let sig = SigInfo { si_signo: SIGSEGV, si_code: SigInfo::KERNEL, si_pid: None };
                task.recv_sigs(sig);
            }
        }
        TrapType::IllegalInstruction(_) => {
            println!("[trap_handler] IllegalInstruction in application, kernel killed it.");
            // 非法指令：投递 SIGILL（内核来源）。
            let task = current_task().unwrap().clone();
            let sig = SigInfo { si_signo: SIGILL, si_code: SigInfo::KERNEL, si_pid: None };
            task.recv_sigs(sig);
        }
        TrapType::Timer => {
            bump_timer_irq();
            crate::timer::timer::TIMER_MANAGER.check();
            // ★ Preempt: track timeslice consumption
            crate::timer::preempt_tick();
            set_next_trigger();
            #[cfg(feature = "smp")]
            {
                // [观测] 心跳：try-drain console + 周期直写各核进度（feature `heartbeat` 关时为空）。
                crate::diag::heartbeat::on_timer_tick();
                // ★ [帧回收饿死修复] 每拍置 NEED_QUIESCE 标志（廉价、中断安全）；run_until_idle 据此在任务上下文真回收 limbo。
                crate::smp::tlb::mark_need_quiesce();
                // ★ [性能根因] 只在【时间片真到期(need_resched)】才让出，而非每个 tick 都让出（避免调度放大）。
                if current_processor().check_need_resched() {
                    yield_now().await;
                }
            }
            #[cfg(not(feature = "smp"))]
            yield_now().await;
        }
        TrapType::ExternalInterrupt => {
            // 外设中断统一交给设备管理器分派到具体驱动。
            let devices = crate::devices::DEVICE_MANAGER.lock();
            devices.handle_irq();
        }
        #[cfg(feature = "smp")]
        TrapType::SoftwareInterrupt => {
            // ★ IPI:清除硬件挂起位(pending bit)，随后分派至处理函数
            unsafe { Instruction::clear_software_interrupt(); }
            crate::smp::ipi::handle_ipi();
        }
        TrapType::Processed => {}
        other => {
            panic!("[trap_handler] Unsupported trap! {:?}", other);
        }
    }
    // ★ Safety Point ①: Trap return — check if preemption is needed
    // This handles the case where a non-timer trap (syscall, page fault, etc.)
    // took long enough that a timer tick set need_resched in the background.
    // Note: Timer case already has yield_now().await above, but this catches
    // the edge case where the timeslice expired between the yield and here.

    // ★ SMP:检查 pending_exit —— 另一核上的 exec 可能已请求终止本任务。
    // 在本地调用 do_exit，以避免跨核数据竞态。
    #[cfg(feature = "smp")]
    {
        let task = current_task().unwrap().clone();
        if task.pending_exit.load(Ordering::Acquire) {
            task.do_exit(0);
        }
    }

    crate::processor::check_preempt().await;
    false
}

