/// 入站 TCP 包摘要（从原始帧解析后传入）
#[derive(Debug, Clone)]
pub struct TcpPacket {
    pub src_ip: Ipv4Address,
    pub dst_ip: Ipv4Address,
    pub src_port: u16,
    pub dst_port: u16,
    pub seq: u32,
    pub ack: u32,
    pub flags: u8,
    pub window: u16,
    pub payload: alloc::vec::Vec<u8>,
}

impl TcpPacket {
    /// 从原始以太网帧解析
    pub fn from_frame(frame: &[u8]) -> Option<Self> {
        use crate::net::wire_util::{EthernetFrame, Ipv4Packet, TcpPacket, EthernetProtocol};

        let eth = EthernetFrame::new_checked(frame).ok()?;
        if eth.ethertype() != EthernetProtocol::Ipv4 {
            return None;
        }

        let ipv4 = Ipv4Packet::new_checked(eth.payload()).ok()?;
        // Check protocol field directly in IPv4 header (byte 9 = protocol)
        if frame.len() < 34 { return None; }
        if frame[23] != 6 { // 6 = TCP protocol number
            return None;
        }
        if ipv4.payload().len() < 20 {
            return None;
        }

        let tcp = TcpPacket::new_checked(ipv4.payload()).ok()?;

        Some(Self {
            src_ip: ipv4.src_addr(),
            dst_ip: ipv4.dst_addr(),
            src_port: tcp.src_port(),
            dst_port: tcp.dst_port(),
            seq: tcp.seq_number().0 as u32,
            ack: tcp.ack_number().0 as u32,
            flags: {
                let mut f = 0u8;
                if tcp.fin() { f |= wire_util::TcpFlags::FIN; }
                if tcp.syn() { f |= wire_util::TcpFlags::SYN; }
                if tcp.rst() { f |= wire_util::TcpFlags::RST; }
                if tcp.psh() { f |= wire_util::TcpFlags::PSH; }
                if tcp.ack() { f |= wire_util::TcpFlags::ACK; }
                f
            },
            window: tcp.window_len(),
            payload: tcp.payload().to_vec(),
        })
    }

    /// 获取源端点
    pub fn src_endpoint(&self) -> IpEndpoint {
        IpEndpoint::new(IpAddress::Ipv4(self.src_ip), self.src_port)
    }

    /// 获取目标端点
    pub fn dst_endpoint(&self) -> IpEndpoint {
        IpEndpoint::new(IpAddress::Ipv4(self.dst_ip), self.dst_port)
    }

    /// 是否为 SYN 包
    pub fn is_syn(&self) -> bool {
        (self.flags & wire_util::TcpFlags::SYN) != 0
            && (self.flags & wire_util::TcpFlags::ACK) == 0
    }

    /// 是否为 SYN-ACK 包
    pub fn is_syn_ack(&self) -> bool {
        (self.flags & wire_util::TcpFlags::SYN) != 0
            && (self.flags & wire_util::TcpFlags::ACK) != 0
    }

    /// 是否为纯 ACK
    pub fn is_pure_ack(&self) -> bool {
        (self.flags & wire_util::TcpFlags::ACK) != 0
            && self.payload.is_empty()
            && (self.flags & (wire_util::TcpFlags::SYN | wire_util::TcpFlags::FIN | wire_util::TcpFlags::RST)) == 0
    }

    /// 是否为 FIN 包
    pub fn is_fin(&self) -> bool {
        (self.flags & wire_util::TcpFlags::FIN) != 0
    }

    /// 是否为 RST 包
    pub fn is_rst(&self) -> bool {
        (self.flags & wire_util::TcpFlags::RST) != 0
    }
}

/// 处理入站 TCP 包
pub fn ingress_tcp(conn: &Arc<TcpConnection>, packet: &TcpPacket, port_table: &SpinNoIrqLock<alloc::collections::BTreeMap<u16, Arc<TcpListener>>>) {
    let mut core = conn.core.lock();

    // RST 处理
    if packet.is_rst() {
        log::warn!("[TCP] conn {} RST received, closing", conn.conn_id);
        core.state = TcpFsmState::Closed;
        drop(core);
        conn.read_waker.wake();
        conn.write_waker.wake();
        return;
    }

    // ★ Bug #XX 修复: Established + DATA 路径使用 ABBA-safe 锁序
    // 先处理 ACK，提取信息后 drop core，再锁 rx_buf，最后重新锁 core 更新状态
    // 避免与 tcp_recv 的 rx_buf→core 形成 ABBA 死锁
    if core.state == TcpFsmState::Established {
        // 1. 先处理 ACK（仅需 core，安全）
        if (packet.flags & wire_util::TcpFlags::ACK) != 0 {
            process_ack(conn, &mut core, packet);
        }

        // 2. 处理 DATA（需要 drop core 后再锁 rx_buf）
        if !packet.payload.is_empty() {
            let rcv_nxt = core.rcv_nxt;
            let seq = packet.seq;
            let payload = packet.payload.clone();
            let has_fin = packet.is_fin();
            let shutdown_writing = conn.shutdown_writing.load(core::sync::atomic::Ordering::Acquire);

            // ★ 并发保护：检查是否有上下文正在 ABBA-safe 路径中处理该 conn 的数据
            // 如果有，将当前帧插入 oo_queue，等 inflight 上下文完成后通过 drain_oo_queue 处理
            // 这防止多个上下文用过期 rcv_nxt snapshot 并发判断顺序导致误判 OUT-OF-ORDER
            let is_inflight = conn.data_inflight.load(core::sync::atomic::Ordering::Acquire);

            if !is_inflight && seq == rcv_nxt {
                // 按序到达且无并发处理：进入 ABBA-safe 路径
                conn.data_inflight.store(true, core::sync::atomic::Ordering::Release);
                drop(core);  // ★ 释放 core 锁 — 关键修复

                // 安全锁定 rx_buf（此时不持有 core 锁）
                process_data_impl(conn, rcv_nxt, seq, &payload, has_fin, shutdown_writing);
                // ★ process_data_impl 会在完成后清除 data_inflight 标志
                return;
            } else {
                // 乱序到达 或 有并发处理：插入 oo_queue（仍持有 core 锁）
                let gap = seq.wrapping_sub(rcv_nxt);
                if is_inflight {
                    log::warn!("[DATA_PATH] conn {} seq={} queued (data_inflight=true) rcv_nxt={} gap={}bytes payload_len={}",
                        conn.conn_id, seq, rcv_nxt, gap, payload.len());
                } else {
                    log::warn!("[DATA_PATH] conn {} OUT-OF-ORDER: seq={} > rcv_nxt={} gap={}bytes payload_len={}",
                        conn.conn_id, seq, rcv_nxt, gap, payload.len());
                }
                core.insert_oo_segment(OooSegment { seq, data: payload.to_vec() });
                core.delayed_ack_pending = true;
                conn.egress_pending.store(true, core::sync::atomic::Ordering::Release);
                return;
            }
        }

        // 3b. 无 DATA 仅有 FIN（无需 drop core，不涉及 rx_buf）
        if packet.is_fin() {
            log::info!("[ingress_established] conn {} got FIN -> CloseWait", conn.conn_id);
            core.rcv_nxt = core.rcv_nxt.wrapping_add(1);
            core.state = TcpFsmState::CloseWait;
            core.delayed_ack_pending = true;
