                if buf_len > 0 { conn.tx_buf.lock().advance(buf_len); }
            }
            drop(core);
            conn.egress_pending.store(true, core::sync::atomic::Ordering::Release);
            conn.read_waker.wake();
            return;
        }

        // 3c. 无 DATA 无 FIN 仅有 ACK — 已在 process_ack 处理
        return;
    }

