// ── [core_net AsyncMutex] TCP 连接锁：单核保持 SpinNoIrqLock 不变；多核换 AsyncMutex（持锁中断开启）──
// 单核：`TcpConnLock<T>` 就是 `SpinNoIrqLock<T>` 本身（类型别名），`.lock()`/`.try_lock()` 即原 spinlock 的方法，
//   故 core/tx_buf/rx_buf 的字段类型、构造、以及 NetIrqTask 处理链里所有 `.lock()` 调用点【字节不变】。
// 多核：`TcpConnLock<T>` 包一层 AsyncMutex，`.lock()`→`lock_spin()`（NetIrqTask 处理链专用，中断开启自旋），
//   `.try_lock()`→`try_lock()`（用户上下文专用，失败 EAGAIN 由 net_retry 重试）。不可在用户上下文阻塞
//   等锁（同核 NetIrqTask 持锁会死锁），故用户路径调用点单独 smp-gate 成 try_lock（见 backend/tcp_ops.rs）。
#[cfg(not(feature = "smp"))]
pub type TcpConnLock<T> = SpinNoIrqLock<T>;
#[cfg(feature = "smp")]
pub use tcp_lock_smp::TcpConnLock;
#[cfg(feature = "smp")]
mod tcp_lock_smp {
    use crate::sync::async_mutex::{AsyncMutex, AsyncMutexGuard};
    /// 多核 TCP 连接锁 = AsyncMutex（持锁期间中断开启，timer/网络中断可驱动重传/persist，
    /// 打破"持锁者需中断驱动事件才能释放锁"的死锁）。
    pub struct TcpConnLock<T>(AsyncMutex<T>);
    impl<T> TcpConnLock<T> {
        #[inline(always)]
        pub const fn new(v: T) -> Self { Self(AsyncMutex::new(v)) }
        /// NetIrqTask 处理链专用：阻塞自旋（中断开启）。等价于单核 SpinNoIrqLock::lock 的语义位置。
        #[inline(always)]
        pub fn lock(&self) -> AsyncMutexGuard<'_, T> { self.0.lock_spin() }
        /// 用户上下文专用：非阻塞，失败返回 None（调用方返回 EAGAIN，net_retry 重试）。
        #[inline(always)]
        pub fn try_lock(&self) -> Option<AsyncMutexGuard<'_, T>> { self.0.try_lock() }
    }
}

/// TCP 连接状态枚举
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
pub enum TcpFsmState {
    Closed,
    SynSent,
    SynReceived,
    Established,
    FinWait1,
    FinWait2,
    Closing,
    TimeWait,
    CloseWait,
    LastAck,
    Listen,
}

impl TcpFsmState {
    /// 是否为已连接状态（可以收发数据）
    pub fn is_connected(&self) -> bool {
        matches!(self, TcpFsmState::Established)
    }

    /// 是否为远程已关闭（收到了 FIN）
    /// 包含 TimeWait：已收到远端 FIN 且双方关闭完成，recv 应返回 EOF
    pub fn is_remote_closed(&self) -> bool {
        matches!(self, TcpFsmState::CloseWait | TcpFsmState::LastAck | TcpFsmState::TimeWait)
    }
}

/// 默认 MSS
pub const TCP_MSS: usize = 1460;

/// TCP 发送/接收缓冲区大小
/// ★ 256KB：原 64KB 在 LA 单核 QEMU TCG 下导致 TCP 测试卡死，根因：
///   64KB rx_buf 在 iperf 等大数据量场景下频繁填满 → RECEIVER_BACKPRESSURE
///   触发 → 发送端 yield → 重新调度后再次快速填满 → 接收端任务永远得不到
///   足够 CPU 时间消费数据。256KB 缓冲区下 iperf 128KB 数据一次全部放入，
///   不触发反压，发送端快速完成，调度器正常切换到接收端。
///   RV 不受影响是因为 SBI ecall 的 timer 中断注入机制在 TCG 中更精确。
pub const TCP_BUF_SIZE: usize = 256 * 1024;

/// TimeWait 超时（微秒）：2MSL ≈ 60s
pub const TIME_WAIT_US: u64 = 60_000_000;

/// 乱序队列最大容量
/// ★ egress batch 可一次性发送 35+ 帧（256KB/1460≈175），
/// 且多个 batch 并发时 oo_queue 可能累积大量条目。
/// 设为 1024 以容纳所有并发乱序帧，防止因队列满 pop 导致永久空洞。
pub const OO_QUEUE_MAX: usize = 1024;

/// 最大重传次数（RFC 6298 §5.5 建议 ≥5）
pub const MAX_RETRANSMIT: u32 = 5;

/// 最大 persist 探测次数
pub const MAX_PERSIST_COUNT: u32 = 15;

/// 半连接 SYN 超时（微秒）：30s
pub const SYN_TIMEOUT_US: u64 = 30_000_000;

