//! [5.x] cgroup 资源隔离基础 —— 统一抽象，三资源同构。【仅 SMP 编译；单核零侵入】
//!
//! 前因（之前实现）：内核无任何资源隔离——CPU 由 FIFO+steal 自由竞争、内存只有全局水位 OOM、
//!   I/O 单进程可独占设备锁。一个负载能抢光/撑爆/拖垮其它任务（缺陷#5 关联）。
//! 为什么做：隔离比"安全"更适合本赛道（机制非策略、可量化、可演示），且天然长在已有的
//!   异步调度器 / per-CPU 帧分配 / 块设备之上。本模块先立【统一 cgroup 抽象 + 每任务归属 +
//!   fork 继承 + CPU 时间记账】，把 CPU/内存/IO 三资源放进同一结构，后续逐个接 enforcement。
//! 后果（现在实现）：
//!   - 每个 TaskBlock 持 `Arc<Cgroup>`，fork 继承父 cgroup（隔离的归属语义）；
//!   - CpuController 实时记账 runtime_ns（schedule 进/出累加），weight 接入加权 vruntime；
//!   - MemController/IoController 承载计数与上限（CPU 加权 vruntime + 带宽配额已 enforcement；
//!     mem 正确记账需 hal FrameOwner 绑定，osr hal 暂无该接口 → 本移植仅承载计数、不绑定帧）。
//!   - ★ shared-nothing：记账全是 per-cgroup 原子计数，不引入任何全局临界区。

use core::sync::atomic::{AtomicU64, AtomicUsize, Ordering};
use alloc::sync::Arc;

/// CPU 控制器：份额(weight) + 已用 CPU 时间(runtime_ns) + 带宽闸门(quota/period)。
/// 带宽 enforcement（async 闸门：超额 .await 挂起）见 check_cpu_quota，本结构承载份额与记账。
pub struct CpuController {
    /// 调度份额权重（接 vruntime 加权；越大越多占 CPU）。默认 1024（Linux nice 0）。
    pub weight: AtomicU64,
    /// 本 cgroup 累计已用 CPU 时间（纳秒）。schedule 进/出累加，实时可查。
    pub runtime_ns: AtomicU64,
    /// 每周期配额（纳秒）。0 = 不限。
    pub quota_ns: AtomicU64,
    /// 周期长度（纳秒）。
    pub period_ns: AtomicU64,
    /// [5.1] 本周期起点（纳秒）。lazy 重置：now - start >= period 即开新周期、runtime 清零。
    pub period_start_ns: AtomicU64,
}

/// 内存控制器：已用页 + 上限。正确记账需 FrameTracker 绑 cgroup（osr hal 暂无 FrameOwner），本结构先承载计数与上限。
pub struct MemController {
    pub used_pages: AtomicUsize,
    /// 0 = 不限。
    pub max_pages: AtomicUsize,
}

/// I/O 控制器：令牌桶。enforcement（取令牌不足则 yield）接块设备提交路径。
pub struct IoController {
    /// 当前可用令牌（字节）。lazy 按 rate_bps 补充。
    pub tokens: AtomicU64,
    /// 速率（字节/秒）。0 = 不限。
    pub rate_bps: AtomicU64,
    /// 上次补充令牌的时刻（纳秒），lazy refill 用。
    pub last_refill_ns: AtomicU64,
    /// 累计 I/O 字节数（观测用，per-cgroup IO 用量）。
    pub bytes_used: AtomicU64,
}

/// 一个资源控制组：三资源 + PID 上限，统一抽象。
pub struct Cgroup {
    pub cpu: CpuController,
    pub mem: MemController,
    pub io: IoController,
    pub pids: AtomicUsize,
    /// 0 = 不限。
    pub pids_max: AtomicUsize,
}

impl Cgroup {
    /// 根 cgroup：三资源全不限（默认归属，行为与"无隔离"完全一致 → 零回归）。
    pub fn new_root() -> Arc<Self> {
        Arc::new(Self {
            cpu: CpuController {
                weight: AtomicU64::new(1024),
                runtime_ns: AtomicU64::new(0),
                quota_ns: AtomicU64::new(0),
                period_ns: AtomicU64::new(100_000_000), // 100ms 默认周期
                period_start_ns: AtomicU64::new(0),
            },
            mem: MemController { used_pages: AtomicUsize::new(0), max_pages: AtomicUsize::new(0) },
            io: IoController {
                tokens: AtomicU64::new(0),
                rate_bps: AtomicU64::new(0),
                last_refill_ns: AtomicU64::new(0),
                bytes_used: AtomicU64::new(0),
            },
            pids: AtomicUsize::new(0),
