    /// 初值 0/0 必落后当前世代 → 首次 enable() 即分配。enable 在持 vm_space 锁下调用，故对同一
    /// 地址空间串行，原子字段无并发竞态。
    #[cfg(feature = "smp")]
    asid: core::sync::atomic::AtomicU16,
    #[cfg(feature = "smp")]
    asid_gen: core::sync::atomic::AtomicU64,
