impl UserAddrSpace {

    pub fn new() -> Self {
        #[cfg(feature = "framediag")]
        crate::mm::diag::uvm_new();
        Self {
            page_table: PageTable::new_in(0, FrameAllocator),
            areas: RangeMap::new(),
            brk: VirtAddr(0)..VirtAddr(0),
            #[cfg(feature = "smp")]
            asid: core::sync::atomic::AtomicU16::new(0),
            #[cfg(feature = "smp")]
            asid_gen: core::sync::atomic::AtomicU64::new(0),
        }
    }

    /// [ASID] 确保本地址空间持有【当前世代】的 ASID(落后则重新分配)，返回该 ASID。仅 SMP。
    #[cfg(feature = "smp")]
    fn ensure_asid(&self) -> u16 {
        use core::sync::atomic::Ordering;
        let cur_gen = crate::mm::asid::current_generation();
        if self.asid_gen.load(Ordering::Acquire) != cur_gen {
            let (a, g) = crate::mm::asid::alloc_asid();
            self.asid.store(a, Ordering::Release);
            self.asid_gen.store(g, Ordering::Release);
            a
        } else {
            self.asid.load(Ordering::Acquire)
        }
    }

    /// [ASID] 读本地址空间当前 ASID(供精确 TLB 击落用)。仅 SMP。未分配则 0。
    #[cfg(feature = "smp")]
    pub fn asid(&self) -> u16 {
        self.asid.load(core::sync::atomic::Ordering::Acquire)
    }

    pub fn enable(&self) {
        // ★ [ASID] riscv64+SMP：satp 带 ASID 激活用户页表，切换【不刷 TLB】(ASID 标签区分 TLB 项)。
        //   satp(Sv39): MODE[63:60]=8 | ASID[59:44] | PPN[43:0]；get_token()=MODE|PPN，OR 上 asid<<44。
        //   ASID 分配器保证同世代内每 asid 至多绑一个活地址空间、rollover 全清，故无 stale TLB、免 sfence。
        #[cfg(all(target_arch = "riscv64", feature = "smp"))]
        {
            let asid = self.ensure_asid();
            // ★ 记录本核当前 ASID，供 TLB 精确击落(sfence(asid,vaddr))自取。
            crate::smp::tlb::set_current_asid(asid as usize);
            let satp = self.get_page_table().get_token() | ((asid as usize) << 44);
            unsafe { core::arch::asm!("csrw satp, {}", in(reg) satp, options(nostack)); }
        }
        // 其余架构 / 单核：沿用原 enable_low + 全量刷(无 ASID，行为不变)。
        #[cfg(not(all(target_arch = "riscv64", feature = "smp")))]
        unsafe {
            self.get_page_table().enable_low();
            Instruction::tlb_flush_all();
        }
    }

    /// ★[多核 sysbench 修复] 激活用户页表并返回 (satp, 该 satp 所属 ASID 世代)。与 enable() 行为一致
    ///   (riscv64+smp 带 ASID 切入、不刷 TLB),但额外返回 satp 与世代号,供调用方(switch_page_table)缓存,
    ///   使下次切换在世代未变时可【免锁】直接写 satp——根除同进程多线程每次切换争用共享 vm_space 自旋锁的串行化。
    ///   仅在 ASID 世代翻转或 exec 换页表时才需再次走本(加锁)慢路径重算。
    #[cfg(all(target_arch = "riscv64", feature = "smp"))]
    pub fn activate_and_satp(&self) -> (usize, u64) {
        use core::sync::atomic::Ordering;
        let asid = self.ensure_asid();
        crate::smp::tlb::set_current_asid(asid as usize);
        let satp = self.get_page_table().get_token() | ((asid as usize) << 44);
        unsafe { core::arch::asm!("csrw satp, {}", in(reg) satp, options(nostack)); }
        // ensure_asid 后 self.asid_gen 即为该 asid 所属世代(未分配时本就 == 当前世代)。
        let gen = self.asid_gen.load(Ordering::Acquire);
        (satp, gen)
    }

