/// ★[iozone Min=0 根治·公平让步] 本核 run queue 还有其他就绪任务等待时,文件 IO 完成后主动让出 →
///   避免极快缓存 IO(读 1MB 仅几 µs、比任何时间片都快)的 worker 连续霸占核、并发测量窗口内其他
///   worker 一次没轮到(Min xfer=0)。无竞争(队列空)时不让、不降单流吞吐。
///   ★[性能] 每 2 次文件 IO 才查一次队列长度(per-cpu 原子计数远比每次查 SpinNoIrqLock 轻),把查锁
///   频率降一半;仍保公平——worker 每 2 次 IO 让一次,4 路并发照样轮转,iozone Min 不受影响。
#[cfg(feature = "smp")]
static IO_YIELD_TICK: [core::sync::atomic::AtomicU32; hal::board::MAX_PROCESSORS] =
    [const { core::sync::atomic::AtomicU32::new(0) }; hal::board::MAX_PROCESSORS];
#[inline]
pub async fn io_fair_yield() {
    #[cfg(feature = "smp")]
    {
        use core::sync::atomic::Ordering;
        let cpu = hal::instruction::Instruction::get_tp();
        if cpu < hal::board::MAX_PROCESSORS
            && IO_YIELD_TICK[cpu].fetch_add(1, Ordering::Relaxed) & 1 == 0
            && crate::processor::processor::current_processor()
                .try_unwrap_with_mut_task_queue(|q| q.len())
                .unwrap_or(0)
                > 0
        {
            crate::utils::async_utils::yield_now().await;
        }
    }
}

/// 仅对【常规文件】成立的判定：socket/pipe 这类时序敏感对象返回 false。
/// 用于 IO 带宽限流 + iozone Min=0 公平让步是否参与的统一闸门。
#[cfg(feature = "smp")]
#[inline]
fn handle_is_regular_file(file: &Arc<dyn File>) -> bool {
    matches!(file.inode(), Ok(node) if node.inode_type().is_file())
}

/// syscall: write
pub async fn sys_write(fd: usize, buf: usize, len: usize) -> SysResult {
    let task = current_task().unwrap().clone();
    log::debug!("task {} trying to write fd {}", task.gettid(), fd);
    let file = fd_file(fd)?;
    let payload = reader_slice::<u8>(buf, len)?;
    let written = file.write(payload.to_ref()).await?;
    // [5.3] cgroup IO 带宽强制 + [iozone Min=0 公平让步]：仅对【常规文件】生效——socket/pipe 收发时序
    //   敏感(TCP 每次让步会拖垮吞吐甚至卡死),绝不掺和;只让缓存快文件 IO 的 worker 公平轮转。
    #[cfg(feature = "smp")]
    if handle_is_regular_file(&file) {
        if written > 0 {
            task.cgroup.io_throttle(written as u64).await;
        }
        io_fair_yield().await;

