    pub s_log_block_size: u32,         // 偏移 24
    _reserved0: [u8; 4],               // 偏移 28
    pub s_blocks_per_group: u32,       // 偏移 32
    pub s_inodes_per_group: u32,       // 偏移 40（跳过 4 bytes）
    _reserved1: [u8; 12],              // 偏移 44-55
    pub s_magic: u16,                  // 偏移 56
    _padding0: [u8; 2],                // 偏移 58
    _reserved2: [u8; 28],              // 偏移 60-87
