/// ★ per-inode 锁的 inode 实例。
/// 同一 inode 号通过 Ext4FileSystem::get_inode 复用同一实例（同锁同 FilePageCache）。
pub struct Ext4NativeInode {
    inner: InodeInner,
    inode_number: u32,
    /// per-inode 锁: 保护磁盘 inode 元数据的读-改-写
    disk_inode: SpinSmpLock<Ext4InodeDisk>,
    cache: Arc<FilePageCache>,
    fs: Arc<super::Ext4FileSystem>,
    /// 完整路径（用于调试）
    path: SpinSmpLock<String>,
    /// ★ POSIX unlink-while-open：unlink 使 nlink=0 时置位。表示"目录项已删、但 inode/数据块的真正
    ///   回收推迟到本 inode 最后一个引用(最后一个 open fd)Drop 时"。绝不在 unlink 当场释放,否则正在
    ///   读写该文件的 fd 会失效(iozone -t 删 DUMMY 时 worker 仍 open → read 失败 → worker 退出 → 屏障挂)。
    orphan: core::sync::atomic::AtomicBool,
}

impl Ext4NativeInode {
    /// 创建一个 inode 实例（从磁盘读入）。由 Ext4FileSystem::get_inode 调用以保证唯一性。
    pub fn new(fs: Arc<super::Ext4FileSystem>, inode_num: u32, path: &str) -> Arc<Self> {
        let gd = fs.snapshot_group_of_inode(inode_num);
        let disk_inode = Ext4InodeDisk::read(
            &*fs.block_device,
            &fs.superblock,
            core::slice::from_ref(&gd),
            inode_num,
            &fs.block_cache,
        );

        let raw_mode = disk_inode.i_mode;
        let mode = InodeMode::from_bits_truncate(raw_mode as u32);
        let inner = InodeInner::new(None, mode, disk_inode.size() as usize);
        inner.set_nlink(disk_inode.nlink() as usize);

        // ★ reclaim: 注册本 inode 的 FilePageCache 到全局回收表，使 shrink() 能遍历逐出干净页。
        //   全局回收器仅 SMP 编译；单核无此机制，跳过注册（FilePageCache 本身照常工作）。
        let cache = Arc::new(FilePageCache::new());
        #[cfg(feature = "smp")]
        crate::fs::page::reclaim::PAGE_RECLAIM.register(alloc::sync::Arc::downgrade(&cache));
        Arc::new(Self {
            inner,
            inode_number: inode_num,
            disk_inode: SpinSmpLock::new(disk_inode),
            cache,
            fs,
            path: SpinSmpLock::new(String::from(path)),
            orphan: core::sync::atomic::AtomicBool::new(false),
        })

//! ext4 Journal / WAL — 最小写前日志（jbd2 思路的【同步】实现 + 重放）
//!
//! [4.3] 用 WAL 给 native ext4 的多块元数据修改（create/unlink/rename）提供"全做或全不做"。
//!
//! ★ 本轮修复（前因 → 后果），对照 review：
//!   1. 寻址：原先 `direct_write_block(block 号当扇区号, 4096 buf)` —— direct_write_block 是【512B 扇区】
//!      寻址 → 日志写到错误位置（写进活动 FS 数据区）且单次只写 512B。现改为走 `BlockCache::direct_write`
//!      （内部 block→扇区 ×(block_size/512) 正确转换、整块落盘）。
//!   2. 屏障/顺序：原先无任何 flush。现采用 jbd2 顺序：descriptor → data... → commit；checkpoint → 更新 JSB。
//!      同步 direct_write 在 QEMU/virtio（无回写缓存）下"完成即落盘"，顺序直写即构成屏障；真机带写缓存
//!      需额外 device flush（留待 async Phase B：write_block_async + flush_async）。
//!   3. 重放：原先【完全没有 recover】。现 `recover()` 在 mount 同步扫描日志，发现"有效 descriptor + 匹配
//!      commit 块 + seq > JSB.committed_seq"才重放（幂等：把每个数据块写回真实块号）。
//!   4. 分离完成标记：原先 commit 记录与"完成标记"写同一槽 → 完成标记把 commit 记录清零。现"完成标记"=更新
//!      独立的 JSB 块（slot0）的 committed_seq，commit 块（独立槽）始终保留。
//!   5. 整块日志：原先把 16B 头塞进同块 → 数据被截断 block_size-16。现 jbd2 式：描述符块单列块号、数据块存
//!      【完整】块内容，互不挤占。
//!   6. bounds / 防 panic：MAX_TXN_BLOCKS 上限校验；staged_writes 的 offset 做 clamp（原 offset>len 会下溢 panic）。
//!   7. 锁：`spin::Mutex` → `SpinNoIrqLock`（内核约定，关中断）。commit 同步、不跨 await。
//!
//! 布局（日志区 = 文件系统末尾 JOURNAL_RESERVED 块；journal_start = blocks_count - RESERVED）：
//!   slot0   : JSB（journal superblock）：magic | committed_seq
//!   slot1   : 描述符：magic | seq | count | block_nums[count]（每个 u64）
//!   slot2.. : count 个【整块】数据（顺序对应描述符的 block_nums）
//!   slot 2+count : commit 块：magic | seq | COMMIT_MARK
//!
//! ★ 接线前置（务必）：日志区那 RESERVED 块必须【不被块分配器分配为数据】，否则 commit 直写会覆盖真实文件
//!   数据。recover() 本身是【只读安全】的（无有效日志 magic → 不写任何块），故可放心在 mount 调用；但
//!   commit() 仅应在镜像已为日志区预留空间后接入 create/unlink。

