const JOURNAL_MAGIC: u32 = 0x4A424432; // "JBD2" — descriptor / commit 块魔数
const JSB_MAGIC: u32 = 0x4A534200; // "JSB\0" — journal superblock 魔数
const COMMIT_MARK: u32 = 0xC0FFEE01; // commit 块的标志字

/// 日志区块数（文件系统末尾保留）。
const JOURNAL_RESERVED: u64 = 256;
/// 单事务最多日志的数据块数：slot0(JSB)+slot1(desc)+N(data)+1(commit) ≤ RESERVED，故 N ≤ RESERVED-3。
const MAX_TXN_BLOCKS: usize = (JOURNAL_RESERVED as usize) - 3;

