/// 从 IpEndpoint 推导 IP 版本（用于 PortRegistry key）
fn ipver_from_endpoint(ep: &IpEndpoint) -> PortIpVer {
    match ep.addr {
        IpAddress::Ipv4(_) => PortIpVer::V4,
        IpAddress::Ipv6(_) => PortIpVer::V6,
    }
}

/// 从可选端点推导 IP 版本
fn ipver_from_opt_endpoint(ep: &Option<IpEndpoint>) -> PortIpVer {
    ep.as_ref().map(|e| ipver_from_endpoint(e)).unwrap_or(PortIpVer::V4)
}

impl NetBackend for NetBackendImpl {
    fn tcp_socket(&self) -> Result<u64, SysError> {
        log::info!("[bktcp::tcp_socket] ENTER");
        let handle = self.alloc_handle();
        let socket = Arc::new(crate::net::tcp::socket_api::TcpSocket::new());
        self.tcp_sockets.lock().insert(handle, socket);
        Ok(handle)
    }

    fn tcp_bind(&self, handle: u64, ep: IpEndpoint) -> Result<(), SysError> {
        log::info!("[bktcp::tcp_bind] ENTER handle={} ep={}:{}", handle, ep.addr, ep.port);
        let sockets = self.tcp_sockets.lock();
        let socket = sockets.get(&handle).ok_or(SysError::EBADF)?.clone();
        drop(sockets);

        let mut bind_ep = ep;
        if bind_ep.port == 0 {
            bind_ep.port = self.alloc_port()?;
        }
        log::info!("[tcp_bind] handle {} port {} addr {}", handle, bind_ep.port, bind_ep.addr);
        if !bind_ep.addr.is_unspecified() && bind_ep.addr != IpAddress::Ipv4(self.local_ip) {
            return Err(SysError::EADDRNOTAVAIL);
        }
        // ★ 注册到 PORT_REGISTRY 防止端口被重复分配（协议=Tcp，版本=IPv4，后续可根据 domain 优化）
        let ipver = match ep.addr {
            IpAddress::Ipv6(_) => PortIpVer::V6,
            _ => PortIpVer::V4,
        };
        super::net_impl::PORT_REGISTRY.register(
            make_port_key(bind_ep.port, PortProtocol::Tcp, ipver),
            super::net_impl::PortOwner::TcpConnection(handle),
        )?;
        socket.bind(bind_ep)
    }

    fn tcp_bind_reuse(&self, handle: u64, ep: IpEndpoint) -> Result<(), SysError> {
        let sockets = self.tcp_sockets.lock();
        let socket = sockets.get(&handle).ok_or(SysError::EBADF)?.clone();
        drop(sockets);

        let mut bind_ep = ep;
        if bind_ep.port == 0 {
            bind_ep.port = self.alloc_port()?;
        }
        if !bind_ep.addr.is_unspecified() && bind_ep.addr != IpAddress::Ipv4(self.local_ip) {
            return Err(SysError::EADDRNOTAVAIL);
        }
        // ★ SO_REUSEADDR: 释放旧端口占用后重新注册
        let ipver = match ep.addr {
            IpAddress::Ipv6(_) => PortIpVer::V6,
            _ => PortIpVer::V4,
        };
        super::net_impl::PORT_REGISTRY.register_reuse(
            make_port_key(bind_ep.port, PortProtocol::Tcp, ipver),
            super::net_impl::PortOwner::TcpConnection(handle),
        )?;
        socket.bind(bind_ep)
    }

    fn tcp_listen(&self, handle: u64) -> Result<(), SysError> {
        log::info!("[bktcp::tcp_listen] ENTER handle={}", handle);
        let sockets = self.tcp_sockets.lock();
        let socket = sockets.get(&handle).ok_or(SysError::EBADF)?.clone();
        drop(sockets);

        socket.listen()?;

        let local_ep = socket.local_endpoint.lock().clone().ok_or(SysError::EADDRNOTAVAIL)?;
        log::info!("[tcp_listen] handle {} port {} registered listener", handle, local_ep.port);
        let listen_ep = IpListenEndpoint {
            addr: if local_ep.addr.is_unspecified() { None } else { Some(local_ep.addr) },
            port: local_ep.port,
        };
        let listener = Arc::new(crate::net::tcp::listener::TcpListener::new(listen_ep));
        // ★ Bug #XX 修复：将 listener 引用存入 socket，供 tcp_accept 使用
        // 防止 port_table 被替换后旧 socket 偷走新 socket 的连接
        *socket.listener.lock() = Some(listener.clone());
        // ★ 注册到 port_table 和 PortRegistry（双重注册保持兼容）
        {
            let mut pt = self.port_table.lock();
            pt.insert(local_ep.port, listener.clone());
            log::info!("[tcp_listen] handle {} port {}: port_table now has {} entries: {:?}",
                handle, local_ep.port, pt.len(), 
                pt.keys().collect::<alloc::vec::Vec<_>>());
        }
        // ★ tcp_bind 已将端口注册为 TcpConnection，listen 时需要升级为 TcpListen。
        // 不能用 register()（会因端口已存在返回 EADDRINUSE），必须用 replace() 升级。
        let ipver = ipver_from_opt_endpoint(&*socket.local_endpoint.lock());
        super::net_impl::PORT_REGISTRY.replace(
            make_port_key(local_ep.port, PortProtocol::Tcp, ipver),
            super::net_impl::PortOwner::TcpListen(listener),
        );
        Ok(())
    }

