        // 新段：挂载/卸载时间留 0，仅创建时间取当前秒，挂载计数从零开始。
        let now = get_current_time_sec();
        Self {
            perm: IpcPerm::default(),
            segsz: sz,
            atime: 0,
            dtime: 0,
            ctime: now,
            cpid,
            lpid: 0,
            nattch: 0,
        }
    }

    pub fn attach(&mut self, lpid: usize) {
        // 一次挂载：记录调用方 PID、刷新挂载时间戳、计数自增。
        self.lpid = lpid;
        self.atime = get_current_time_sec();
        self.nattch += 1;
