//! 条件锁：允许内核任务在条件不满足时通过 async waker 机制挂起，
//! 等待条件变为真后再获取锁继续执行。
//!
//! # 用途
//!
//! 替代「先释放自旋锁 → 忙等 → 再抢锁」的轮询模式，适用于内核内部需要
//! 等待某个共享状态被其他任务（或中断下半部）修改的场景。
//!
//! 用户态 `pthread_cond_wait` / `futex(FUTEX_WAIT)` 由已有的 futex 子系统覆盖，
//! 此原语专供内核模块（例如设备驱动、文件系统、网络栈）使用。
//!
//! # 示例
//!
//! ```ignore
//! use crate::sync::condlock::CondVar;
//!
//! static FLAG: CondVar<bool> = CondVar::new(false);
//!
//! // 任务 A — 等待条件
//! async fn waiter() {
//!     let mut guard = FLAG.wait_until(|flag| *flag).await;
//!     // … 条件满足，持有锁 …
//! }
//!
//! // 任务 B — 触発条件
//! fn notifier() {
//!     let mut guard = FLAG.lock();
//!     *guard = true;
//!     // 在释放 guard 后，或显式调用 notify_one
//! }
//! ```

use core::ops::{Deref, DerefMut};
use core::task::Waker;

use alloc::collections::vec_deque::VecDeque;

use crate::sync::mutex::spin_mutex::MutexGuard;
#[cfg(feature = "smp")]
use crate::sync::mutex::SpinSmp;
#[cfg(not(feature = "smp"))]
use crate::sync::mutex::SpinNoIrq as SpinSmp;
use crate::sync::mutex::SpinSmpLock;
use crate::utils::{get_waker, suspend_now};

/// 条件锁。
///
/// 包装一个 `SpinSmpLock<T>` 和一个等待队列 `VecDeque<Waker>`，
/// 通过 `wait_until` 让任务在条件不满足时挂起，而非忙等。
///
/// `CondVar<T>` 本身是 `Sync + Send`（只要 T: Send），因为内部的自旋锁
/// 提供了线程安全的保护。
///
/// [`CondWaitGuard`] 返回的 guard **不支持**跨越 `.await` 持有（因为底层
/// `MutexGuard` 是 `!Send`），这是安全设计，防止死锁。
pub struct CondVar<T> {
    /// 受保护的内核数据
    inner: SpinSmpLock<T>,
    /// 等待条件为真的任务 waker 队列
    waiters: SpinSmpLock<VecDeque<Waker>>,

