const VIRTIO0: usize = 0x10001000 | Constant::KERNEL_ADDR_SPACE.start;

// ★ SMP-safe: SpinNoIrqLock 串行化 VirtIOBlk virtqueue 操作
// 不可替代性: virtqueue 是共享硬件状态，多核并发写入导致 DMA token 错乱 (WrongToken)。
pub struct VirtIOBlock(
    #[cfg(feature = "smp")]
    SpinNoIrqLock<VirtIOBlk<VirtioHal, MmioTransport>>,
    #[cfg(not(feature = "smp"))]
    UPSafeCell<VirtIOBlk<VirtioHal, MmioTransport>>,
);

impl BlockDevice for VirtIOBlock {

    fn size(&self) -> u64 {
        #[cfg(feature = "smp")]
        { self.0.lock().capacity() * (BLOCK_SIZE as u64) }
        #[cfg(not(feature = "smp"))]
        { self.0.exclusive_access().capacity() * (BLOCK_SIZE as u64) }
    }

    fn block_size(&self) -> usize {
        BLOCK_SIZE
    }
    fn read_block(&self, block_id: usize, buf: &mut [u8]) {
        #[cfg(feature = "smp")]
        { self.0.lock().read_blocks(block_id, buf).expect("Error when reading VirtIOBlk"); }
        #[cfg(not(feature = "smp"))]
        { self.0.exclusive_access().read_blocks(block_id, buf).expect("Error when reading VirtIOBlk"); }
    }
    fn write_block(&self, block_id: usize, buf: &[u8]) {
        #[cfg(feature = "smp")]
        { self.0.lock().write_blocks(block_id, buf).expect("Error when writing VirtIOBlk"); }
        #[cfg(not(feature = "smp"))]
        { self.0.exclusive_access().write_blocks(block_id, buf).expect("Error when writing VirtIOBlk"); }
    }
}

impl VirtIOBlock {
    #[allow(unused)]
    pub fn new() -> Self {
        // 将固定 MMIO 基址包装成 VirtIO header 指针，再建立 4KiB 窗口的传输层。
        unsafe {
            let hdr_ptr = core::ptr::NonNull::new(VIRTIO0 as *mut VirtIOHeader).unwrap();
            let transport = MmioTransport::new(hdr_ptr, 4096).unwrap();
            let driver = VirtIOBlk::<VirtioHal, MmioTransport>::new(transport)
                .expect("failed to create blk driver");
            // 单核走 UPSafeCell，多核改用 SpinNoIrqLock 串行化 virtqueue。
            #[cfg(feature = "smp")]
            let cell = SpinNoIrqLock::new(driver);
            #[cfg(not(feature = "smp"))]
            let cell = UPSafeCell::new(driver);
            Self(cell)
        }
    }
}

