        // 表驱动：把“裸数值 → 套接字种类”的对应关系集中成一张表，逐项线性查。
        const TABLE: &[(i32, SocketType)] = &[
            (1, SocketType::STREAM),
            (2, SocketType::DGRAM),
            (3, SocketType::RAW),
            (4, SocketType::RDM),
            (5, SocketType::SEQPACKET),
            (6, SocketType::DCCP),
            (10, SocketType::PACKET),
        ];
        TABLE
            .iter()
            .find_map(|&(code, kind)| (code == raw).then_some(kind))
            .ok_or(Self::Error::EINVAL)
    }
}

