#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
pub enum PageLevel {
    Huge = 0,
    Big = 1,
    Middle = 2,
    Small = 3
}

impl PageLevel {
    pub const fn page_count(self) -> usize {
        match self {
            PageLevel::Huge => 512 * 512 * 512,
            PageLevel::Big => 512 * 512,
            PageLevel::Middle => 512,
            PageLevel::Small => 1,
        }
    }

    pub const fn lower(self) -> Self {
        match self {
            PageLevel::Huge => PageLevel::Big,
            PageLevel::Big => PageLevel::Middle,
            PageLevel::Middle => PageLevel::Small,
            PageLevel::Small => PageLevel::Small,
        }
    }

    pub const fn higher(self) -> Self {
        match self {
            PageLevel::Huge => PageLevel::Huge,
            PageLevel::Big => PageLevel::Huge,
            PageLevel::Middle => PageLevel::Big,
            PageLevel::Small => PageLevel::Middle,
        }
    }

    pub const fn lowest(self) -> bool {
        match self {
            PageLevel::Small => true,
            _ => false
        }
    }

    pub const fn highest(self) -> bool {
        match self {
            PageLevel::Huge => true,
            _ => false
        }
    }

    pub const fn from_count(count: usize) -> Option<Self> {
        match count {
            0x1 => Some(Self::Small),
            0x200 => Some(Self::Middle),
            0x40000 => Some(Self::Big),
            0x8000000 => Some(Self::Huge),
            _ => None
        }
    }
}

impl From<usize> for PageLevel {
    fn from(value: usize) -> Self {
        match value {
            0 => Self::Huge,
            1 => Self::Big,
            2 => Self::Middle,
            3 => Self::Small,
            _ => panic!("unsupport Page Level")
        }

//! TLB 击落(TLB Shootdown)：跨核 TLB 一致性维护。
//!
//! 基本原理：
//! 1. 修改页表项(PTE)。
//! 2. 本地 hart 立即刷写(flush)其 TLB。
//! 3. 向所有其他 hart 广播 IPI。
//! 4. 其他 hart 在收到 IPI 时刷写各自的 TLB。
//!
//! 在修改一个既有 PTE 之后(解除映射、变更权限)，应使用 `tlb_shootdown_addr`。
//! 对于新建映射(其他核上不可能存在过期的 TLB 表项)，应使用 `local_flush_tlb_addr`。

use hal::instruction::{Instruction, InstructionHal};

#[cfg(feature = "smp")]
use crate::smp::ipi::{broadcast_ipi_except, IpiKind};
#[cfg(feature = "smp")]
use crate::processor::processor::current_processor;

// ★ [ASID 阶段2] per-cpu「当前核激活的用户地址空间 ASID」。enable() 切入用户页表时写入；
//   TLB 击落(总是针对当前核当前任务的 vmspace)据此自取 asid 做精确 sfence，无需把 asid 穿过
//   VmRegion 的每个方法。远端经 IPI 收到该 asid，sfence(asid,vaddr) 不受其自身当前 asid 影响。
#[cfg(all(target_arch = "riscv64", feature = "smp"))]
static CURRENT_ASID: [crate::sync::cache_aligned::CacheAligned<core::sync::atomic::AtomicUsize>;
    hal::board::MAX_PROCESSORS] =
    [const { crate::sync::cache_aligned::CacheAligned::new(core::sync::atomic::AtomicUsize::new(0)) };
        hal::board::MAX_PROCESSORS];

/// enable() 切入用户页表时记录本核当前 ASID（供击落取用）。
#[cfg(all(target_arch = "riscv64", feature = "smp"))]
pub fn set_current_asid(asid: usize) {
    let cpu = Instruction::get_tp();
    CURRENT_ASID[cpu].store(asid, core::sync::atomic::Ordering::Relaxed);
}

/// 取本核当前 ASID。
#[cfg(all(target_arch = "riscv64", feature = "smp"))]
#[inline]
fn current_asid() -> usize {
    let cpu = Instruction::get_tp();
    CURRENT_ASID[cpu].load(core::sync::atomic::Ordering::Relaxed)
}

/// 针对单个地址的本地 TLB 刷写。
/// 用于**新建映射**——此时其他核上不可能存在过期的 TLB 表项。
#[inline(always)]
pub fn local_flush_tlb_addr(vaddr: usize) {
    unsafe { Instruction::tlb_flush_addr(vaddr); }
}

/// ★ [ASID 阶段2] os 层【精确】单页击落：`sfence.vma vaddr, asid`（rs2=asid 寄存器，非 x0 →
/// 仅作用该 ASID 的该页 TLB 项）。HAL 的 `tlb_flush_addr` 写死 asid=0 刷不到 asid!=0 的项，
/// 故 os 自带此 asm（不改 HAL 实现，属"在 os 层换调用方式"的允许绕法）。仅 riscv64。
#[cfg(all(target_arch = "riscv64", feature = "smp"))]
#[inline(always)]
pub(crate) unsafe fn sfence_vma_asid(asid: usize, vaddr: usize) {
    core::arch::asm!("sfence.vma {0}, {1}", in(reg) vaddr, in(reg) asid, options(nostack));
}

/// 本地全量 TLB 刷写。
#[inline(always)]
pub fn local_flush_tlb_all() {
    unsafe { Instruction::tlb_flush_all(); }
}

/// TLB 击落(TLB Shootdown)：在所有核上刷写某个特定地址。
///
/// 应在修改一个既有 PTE **之后**调用(解除映射、写时复制(CoW)权限变更等)。
/// SMP 情形下：本地刷写 + 向所有其他核广播 IPI。
/// 非 SMP 情形下：仅本地刷写(行为无任何改变)。
#[cfg(feature = "smp")]
pub fn tlb_shootdown_addr(vaddr: usize) {
    // ★ [ASID 阶段2] riscv64+SMP：按 (vaddr, 当前核 ASID) 精确刷——本地 sfence(asid,vaddr)，
    //   远端经 IPI 携 asid 各自 sfence(asid,vaddr)，只击落该地址空间的该页（不再全量刷 TLB）。
    #[cfg(target_arch = "riscv64")]
    {
        let asid = current_asid();
        unsafe { sfence_vma_asid(asid, vaddr); }
        let self_cpu = current_processor().id();
        broadcast_ipi_except(self_cpu, IpiKind::TlbShootdown, vaddr, asid);
    }

//! 处理器间中断(Inter-HartCpu Interrupt, IPI)处理。
//!
//! IPI 类型:
//! - `TlbShootdown`:请求目标核刷写(flush)针对某一特定地址(或全部)的 TLB 表项。
//! - `Resched`:请求目标核重新调度。
//!
//! 消息以 per-CPU 无锁原子量传递。针对不同地址的多个 TLB 击落若发生竞态，
//! 会被合并成一次全量刷写——保守但始终安全。
//!
//! ★ TLB 待处理状态编码进**单个** `AtomicUsize`（取代旧的"全量标志 + 地址槽"两个原子量）：
//!   值 0 = 无待处理；bit0 置位 = 全量刷写；其余非 0 值 = 待刷的单个页地址。
//!   页地址天然页对齐（低 12 位为 0），故 bit0 可安全借作全量标志，与真实地址不冲突。
//!   合一的意义：接收端一次 `swap` 即取走全部 TLB 状态，消除旧版"先读全量标志、再读地址"
//!   两次独立 swap 之间被新请求插入而漏读的窗口。

use core::sync::atomic::{AtomicBool, AtomicUsize, Ordering};

use hal::board::MAX_PROCESSORS;
use hal::instruction::{Instruction, InstructionHal};

/// `tlb` 字段里标记"全量刷写"的位（借用页对齐地址恒为 0 的最低位）。
const TLB_FLUSH_ALL: usize = 1;

/// IPI 消息种类。
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum IpiKind {
    /// TLB 击落:目标核必须刷写针对给定地址的 TLB(0 表示刷写全部)。
    TlbShootdown,
    /// 重新调度请求。
    Resched,
}

/// per-CPU 的待处理 IPI 状态(无锁原子量)。
struct PerCpuIpi {
    /// 待处理 TLB 击落（单字段编码）：0=无；bit0(`TLB_FLUSH_ALL`) 置位=全量刷写；
    /// 其余非 0=待刷页地址。地址冲突或显式全量请求都会把它升级为含 bit0 的全量。
    tlb: AtomicUsize,
    /// 待处理的重新调度请求。
    resched: AtomicBool,
}

impl PerCpuIpi {
    const fn new() -> Self {
        Self {
            tlb: AtomicUsize::new(0),
            resched: AtomicBool::new(false),
        }
    }
}

/// per-CPU 的待处理 IPI 槽位。以 hart/CPU ID 为索引。
static mut PER_CPU_IPI: [PerCpuIpi; MAX_PROCESSORS] =
    [const { PerCpuIpi::new() }; MAX_PROCESSORS];

/// 获取当前 CPU 的 IPI 槽位。
fn current_cpu_id() -> usize {
    Instruction::get_tp()
}

