///   用户 Sv39 vaddr < 2^39，故 bits[47:39] 恒 0，可安全借 bits[63:48] 装 ASID，互不冲突。
const TLB_ASID_SHIFT: usize = 48;
const TLB_VADDR_MASK: usize = (1usize << TLB_ASID_SHIFT) - 1;

/// 向 `target_cpu` 提交一个 TLB 击落 IPI（写入单字段 `tlb` 编码，含 ASID）。
