/// 一个目录所有 32 字节槽位的磁盘绝对偏移（按链顺序），用于反向清 LFN/原地改。
fn slot_offsets(bdev: &dyn BlockDevice, cache: &BlockCache, bpb: &Bpb, dir_first_cluster: u32) -> Vec<u64> {
    let mut offs = Vec::new();
    let chain = fat::follow_chain(bdev, cache, bpb, dir_first_cluster);
    let bps = bpb.bytes_per_sector as u64;
    let spc = bpb.sectors_per_cluster as u64;
    let per_sec = (bps / 32) as u64;
    for &cl in &chain {
        let first_sec = bpb.cluster_to_sector(cl);
        for s in 0..spc {
            let sec = first_sec + s;
            for e in 0..per_sec {
                offs.push(sec * bps + e * 32);
            }
        }
    }
    offs
}

