pub struct LoopDevInode {
    inner: InodeInner,
    file: SpinNoIrqLock<Option<Arc<dyn File>>>,
    loop_info: SpinNoIrqLock<Option<LoopInfo>>,
    loop_info64: SpinNoIrqLock<Option<LoopInfo64>>,
    binding_owner_pid: AtomicUsize,
}

impl LoopDevInode {
    pub fn new() -> Arc<Self> {
        let meta = InodeInner::new(None, InodeMode::BLOCK, 0);
        Arc::new(Self {
            inner: meta,
            file: SpinNoIrqLock::new(None),
            loop_info: SpinNoIrqLock::new(None),
            loop_info64: SpinNoIrqLock::new(None),
            binding_owner_pid: 0.into(),
        })
    }

    /*
     * ★ [LTP 适配-20260505-P0-loop-owner-exit]
     * 背景：`tst_attach_device()` 在发完 `LOOP_SET_FD` / `LOOP_SET_STATUS` 之后会马上把 `dev_fd` 关掉，
     * 所以不能简单地用“是否还存在没关闭的 `/dev/loop0` 控制 fd”来判断绑定该不该结束。
     * 解决办法：额外记下“建立绑定的进程是谁”，只有当那个进程意外退出、且绑定还没被释放时，才做善后清理。
     */
    pub fn add_file(&self, file: Arc<dyn File>, owner_pid: usize) -> Result<(), SysError> {
        match self.file.lock().is_some() {
            true => return Err(SysError::EBUSY),
            false => {}
        }
        *self.file.lock() = Some(file);
        *self.loop_info.lock() = LoopInfo::default().into();
        *self.loop_info64.lock() = LoopInfo64::default().into();
        self.binding_owner_pid.store(owner_pid, Ordering::Release);
        Ok(())
    }

    pub fn is_bound(&self) -> bool {
        self.file.lock().is_some()
    }

    pub fn clear(&self) -> Result<(), SysError> {
        if !self.is_bound() {
            return Err(SysError::ENXIO);
        }
        self.file.lock().take();
        self.loop_info.lock().take();
        self.loop_info64.lock().take();
        self.binding_owner_pid.store(0, Ordering::Release);
        Ok(())
    }

    pub fn binding_owner_pid(&self) -> usize {
        self.binding_owner_pid.load(Ordering::Acquire)
    }

    pub fn clear_on_owner_exit(&self, exiting_pid: usize) -> bool {
        if exiting_pid == 0 || self.binding_owner_pid() != exiting_pid || !self.is_bound() {
            return false;
        }
        match self.clear() {
            Ok(()) => {
                log::info!("[Loop] auto-cleared on owner exit, pid={}", exiting_pid);
                true
            }
            Err(why) => {
                log::warn!("[Loop] owner-exit auto-clear failed for pid {}: {:?}", exiting_pid, why);
