/// 顺序预读单步增量(页)：检测到顺序流后，预读窗口每次按此步长增大。
const READAHEAD_STEP_PAGES: usize = 4;
/// 顺序预读窗口上限(页)：32KiB，足够覆盖 iozone 类小文件顺序流，又不至于读放大。
const READAHEAD_MAX_PAGES: usize = 8;

pub struct FilePageCache {
    /// 由文件偏移（须页对齐）映射到对应的缓存页。
    /// TODO：当前借助 BTreeMap 让回刷按偏移从低到高进行，
    /// 以规避 “Seek Beyond file size” 的问题；文件系统是否应当支持这种情形仍待确认。
    pages: SpinNoIrqLock<BTreeMap<usize, Arc<Page>>>,
    /// EOF 所在位置。
    /// 记录它是为了避免无休止地读取；
    /// 需要留意：缓存写入可能撑大文件，因此该值届时也要随之更新。
    end: AtomicUsize,
    /// [预读] 上一次触发读盘(miss)的页偏移：用于判定本次访问是否顺序衔接(off == prev+PAGE)。
    ra_prev: AtomicUsize,
    /// [预读] 当前顺序预读窗口(页)：顺序流时按步长增长至上限，随机访问归零(零预取、不伤随机)。
    ra_window: AtomicUsize,
}

impl FilePageCache {
    /// 构造一份新的页缓存
    pub fn new() -> Self {
        Self {
            pages: SpinNoIrqLock::new(BTreeMap::new()),
            end: AtomicUsize::new(0usize),
            ra_prev: AtomicUsize::new(usize::MAX), // MAX 表示尚无历史，首次访问必判为非顺序
            ra_window: AtomicUsize::new(0usize),
        }
    }
    /// 取得缓存内部的页映射结构
    pub fn get_pages(&self) -> &SpinNoIrqLock<BTreeMap<usize, Arc<Page>>> {
        &self.pages
    }
    /// 按文件偏移取出对应的缓存页
    pub fn get_page(&self, offset: usize) -> Option<Arc<Page>> {
        assert!(offset % PAGE_SIZE == 0);
        self.pages.lock().get(&offset).cloned()
    }
    /// 按文件偏移把一张【已就绪的完整页】插入缓存（覆盖式）。调用者须保证 page 数据已填好；
    /// 这里统一 set_ready 兜底，确保缓存中不残留 ready=false 的页(否则并发 wait_ready 会死自旋)。
    pub fn insert_page(&self, offset: usize, page: Arc<Page>) {
        assert!(offset % PAGE_SIZE == 0);
        page.set_ready();
        self.pages.lock().insert(offset, page);
        // ★ SMP：向全局回收器登记新增的一页；水位过高时会触发收缩（逐出干净页，腾出页帧供用户分配）。单核构建下不编译此分支，整体行为不受影响。
        #[cfg(feature = "smp")]
        crate::fs::page::reclaim::PAGE_RECLAIM.add_page();
    }

    /// ★ FilePageCache miss 填充双检锁 / single-flight：
