fn task_state_char(status: RunState) -> char {
    match status {
        RunState::Running => 'R',
        RunState::Ready => 'R',
        RunState::Interruptable => 'S',
        RunState::UnInterruptable => 'D',
        RunState::Stopped => 'T',
