#[deprecated = "unsafe"]
/// 借助页表把一个指针解析成若干段可变 u8 切片组成的 Vec
pub unsafe fn translated_byte_buffer(token: usize, ptr: *const u8, len: usize) -> Vec<&'static mut [u8]> {
    let pt = PageTable::from_token(token, FrameAllocator);
    let tail = ptr as usize + len;
    let mut segments = Vec::new();
    let mut cursor = ptr as usize;
    // 逐页推进：每轮处理 cursor 所在物理页中尚未覆盖的那一段
    while cursor < tail {
        let va_lo = VirtAddr::from(cursor);
        let vpn = va_lo.floor();
        // 当前页的下一页起始地址即为本段的（候选）上界
        let next_page_va: VirtAddr = (vpn + 1).start_addr();
        let va_hi = next_page_va.min(VirtAddr::from(tail));
        let frame_pa = pt.translate_vpn(vpn).unwrap().start_addr();
        let lo = va_lo.page_offset();
        // page_offset 为 0 说明本段恰好抵达页末尾，需取到页尾
        match va_hi.page_offset() {
            0 => segments.push(&mut frame_pa.get_mut::<[u8; 4096]>()[lo..]),
            hi => segments.push(&mut frame_pa.get_mut::<[u8; 4096]>()[lo..hi]),
        }
        cursor = va_hi.0;
    }
    segments
}

#[deprecated = "unsafe"]
/// 经页表把指向以 `\0` 结尾字节序列的指针转换为 `String`
pub unsafe fn translated_str(token: usize, ptr: *const u8) -> String {
    let pt = PageTable::from_token(token, FrameAllocator);
    let mut text = String::new();
    let mut cursor = ptr as usize;
    // 逐字节翻译，遇到 NUL 即收尾；翻译失败沿用原行为直接 panic
    loop {
        let pa = pt.translate_va(VirtAddr::from(cursor)).unwrap();
        let byte: u8 = *pa.get_mut();
        if byte == 0 {
            break;
        }
        text.push(byte as char);
        cursor += 1;
    }
    text
}


