pub const NET_QUEUE_SIZE: usize = 64;
// ★[借鉴·Chronix] 下 11 行沿用自 Chronix:os/src/drivers/net/virtio_net.rs
pub struct VirtIoNetDev<T: Transport> {
    rx_buffers: [Option<NetBufBox>; NET_QUEUE_SIZE],
    tx_buffers: [Option<NetBufBox>; NET_QUEUE_SIZE],
    free_tx_bufs: Vec<NetBufBox>,
    buf_pool: Arc<NetBufPool>,
    raw_device: VirtIONetRaw<VirtioHal, T, NET_QUEUE_SIZE>,
}

unsafe impl<T: Transport> Send for VirtIoNetDev<T> {}
unsafe impl<T: Transport> Sync for VirtIoNetDev<T> {}
impl<T: Transport> VirtIoNetDev<T> {
    /// 创建一个 VirtIoNetDev 实例
    pub fn new(transport: T) -> DevResult<Box<Self>> {
        const NONE_BUF: Option<NetBufBox> = None;
        // 共享缓冲池容量为收发两端队列长度之和
        let pool = NetBufPool::new(NET_QUEUE_SIZE * 2, NET_BUF_LEN)?;
        let mut dev = Self {
            rx_buffers: [NONE_BUF; NET_QUEUE_SIZE],
            tx_buffers: [NONE_BUF; NET_QUEUE_SIZE],
            free_tx_bufs: Vec::with_capacity(NET_QUEUE_SIZE),
            buf_pool: pool,
            raw_device: VirtIONetRaw::new(transport).map_err(as_dev_err)?,
        };

        // 接收侧：把每个槽位都挂上一块缓冲区，token 必须与槽位下标一一对应
        for slot_idx in 0..NET_QUEUE_SIZE {
            let mut rx_buf = dev.buf_pool.alloc_boxed().ok_or(DeviceErr::NoMemory)?;
            let token = unsafe {
                dev.raw_device
                    .receive_begin(rx_buf.as_mut_slice())
                    .map_err(as_dev_err)?
            };
            assert_eq!(token, slot_idx as u16);
            dev.rx_buffers[slot_idx] = Some(rx_buf);
        }

        // 发送侧：预填报文头后放入空闲列表，等待后续 alloc 取用
        for _ in 0..NET_QUEUE_SIZE {
            let mut tx_buf = dev.buf_pool.alloc_boxed().ok_or(DeviceErr::NoMemory)?;
            let header_len = dev
                .raw_device
                .fill_buffer_header(tx_buf.as_mut_slice())
                .or(Err(DeviceErr::InvalidParam))?;
            tx_buf.set_header_len(header_len);
            dev.free_tx_bufs.push(tx_buf);
        }

        Ok(Box::new(dev))
    }
 }

