//! AsyncMutex — 异步互斥锁（基于 WakerCell）
//!
//! ★ 核心设计：持锁期间中断保持开启（不使用 SieGuard），等待时 yield 而非关中断 spin。
//! - try_lock(): 非阻塞，用户上下文专用（tcp_send/recv/poll）
//! - lock_spin(): 阻塞自旋（中断开启），NetIrqTask 处理链专用
//! - lock(): 异步等待（yield + wake），保留给未来使用
//!
//! 不可替代性：SpinNoIrqLock 持锁期间关中断，若持锁者需要 timer/网络中断驱动事件
//! 才能释放锁（如等 ACK 推进 snd_una），形成永久死锁。AsyncMutex 持锁期间中断开启，
//! timer 可正常触发重传/persist，打破循环依赖。

use core::cell::UnsafeCell;
use core::ops::{Deref, DerefMut};
use core::sync::atomic::{AtomicBool, Ordering};
use crate::net::waker::WakerCell;

/// ★ 异步互斥锁
pub struct AsyncMutex<T> {
    /// CAS 获取标志：false=空闲, true=已锁
    locked: AtomicBool,
    /// 等待者唤醒器（单槽，竞态安全 — WakerCell 内置 pending 补偿）
    waker: WakerCell,
    /// 受保护数据
    data: UnsafeCell<T>,
}

unsafe impl<T: Send> Send for AsyncMutex<T> {}
unsafe impl<T: Send> Sync for AsyncMutex<T> {}

/// AsyncMutex 守卫
pub struct AsyncMutexGuard<'a, T> {
    mutex: &'a AsyncMutex<T>,
}

impl<'a, T> !Sync for AsyncMutexGuard<'a, T> {}
impl<'a, T> !Send for AsyncMutexGuard<'a, T> {}

impl<T> AsyncMutex<T> {
    pub const fn new(data: T) -> Self {
        Self {
            locked: AtomicBool::new(false),
            waker: WakerCell::new(),
            data: UnsafeCell::new(data),
        }
    }

    /// ★ 非阻塞 try_lock — 用户上下文专用。
    /// 成功返回 guard，失败返回 None（调用方返回 EAGAIN）。
    /// 不可替代性：用户任务不能阻塞等待锁（否则 yield 期间 TCB 切换但 guard 在栈上），
    /// 必须 try_lock + EAGAIN 让 net_retry 处理重试。

