fn add_awaiter(manager: &mut FutexShard, task: &Arc<TaskBlock>, key: FutexHashKey, mask: u32) {
    task.set_interruptable();
    // 阻塞期间允许被「未被屏蔽」的信号唤醒。
    task.set_wake_up_sigs(task.with_sig_manager(|sig| !sig.blocked_sigs));
    let waiter = FutexWaiter {
        tid: task.tid(),
        waker: task.waker().clone().unwrap(),
        mask,
    };
    manager.add_waiter(&key, waiter)
}

/// 把一个用户态地址解析成对应的 [`FutexHashKey`]：私有 futex 直接用
/// (mm, vaddr) 标识；共享 futex 则先把虚拟地址翻译成物理地址再以 paddr 标识。
fn resolve_key(
    task: &Arc<TaskBlock>,
    addr: usize,
    is_private: bool,
) -> Result<FutexHashKey, SysError> {
    let vaddr = VirtAddr::from(addr);
    if is_private {
        return Ok(FutexHashKey::Private {
            mm: task.get_raw_vm_ptr(),
            vaddr,
        });
    }
    let paddr = task.with_mut_vm_space(|space| {
        translate_uva_checked(space, vaddr, MemAccessKind::WRITE).ok_or(SysError::EINVAL)
    })?;
    Ok(FutexHashKey::Shared { paddr })
}

