/// 抽象出定时器触发时所要执行动作的 trait。
/// 实现方需各自给出 callback，定时器一旦到点便会调用它。
pub trait TimerEvent: Send + Sync {
    /// 定时器触发瞬间运行的回调。
    /// 调用会取走事件本身的数据，并可能给出一个后继定时器。
    ///
    /// # 返回值
    /// 若返回 Some(Timer)，则用其安排下一轮触发。
    fn callback(self: Box<Self>) -> Option<Timer>;
}

/// 把到期时刻和到期所需事件数据捆在一起的定时器结构。
/// 既记录何时触发，也保存触发时处理事件要用的数据。
pub struct Timer {
    /// 计划触发的那一时刻，也就是定时器的到期时间。
    pub expire: Duration,

    /// 经装箱的 TimerEvent trait 对象，
    /// 借此让各种事件类型都能搭载在定时器之上。
    pub data: Box<dyn TimerEvent>,
}

impl Timer {
    /// 创建一个 Timer
    pub fn new(expire: Duration, data: Box<dyn TimerEvent>) -> Self {
        Self { expire, data }
    }

    /// 创建一个触发时去唤醒指定 Waker 的 Timer
    pub fn new_waker_timer(expire: Duration, wake_handle: Waker) -> Self {
        // 一个仅持有 Waker 的最小事件：到点即唤醒，无后继定时器。
        struct WakerData(Waker);
        impl TimerEvent for WakerData {
            fn callback(self: Box<Self>) -> Option<Timer> {
                #[cfg(feature = "smp")]
                log::debug!("[timer_waker] callback fired");
                self.0.wake();
                None
            }
        }
        Self::new(expire, Box::new(WakerData(wake_handle)))

//! [6.2] per-core 飞行记录仪 —— 超越 backtrace 的跨核因果时间线
//!
//! 前因（之前实现）：内核出错只有 panic 的 backtrace（`hal::util::backtrace`）。对 SMP 内核，
//!   真正的 bug 是【并发交错】（如 epoch reclaim race、block cache TOCTOU、stale-TLB-after-free），
//!   单核 backtrace 只给"一个核的一根栈"——看不到"出事前别的核在干什么"，对并发 bug 几乎无用。
//! 为什么优化：给每核一个无锁 ring buffer，常驻记录最近事件（IPI/调度/缺页/锁/TLB…），任何
//!   故障时连同 backtrace 一起 dump → 提供【跨核时间线（因果）】，严格比单核栈更真。
//! 后果（现在实现）：per-core `UnsafeCell<[Event; RING]>` + 原子 head（本核单写；仅 crash/停机读）。
//!
//! ★ 本轮两处修复：
//!   1. **弱内存发布顺序（RVWMO/U74 板上才咬人）**：原先"先 fetch_add head 再写槽"且全 Relaxed，
//!      跨核 dump 可读到"已发布但未写"的撕裂事件。现：payload 先写 → Release fence → 最后写 `seq`
//!      作为"有效"标记（类比 pstore magic-last）；dump 端先 Acquire fence 再读，`seq!=0` ⇒ payload 完整。
//!   2. **收进 `diag` feature（默认关）**：record/dump 在 feature 关时编译为空 no-op，
//!      → 性能/竞赛/上板构建【零开销】，且消除每次调度/syscall 都 RMW 的【全局竞争 SEQ】（最大单点损耗）。
//!      调试时 `make ... DIAG=1` 开启即得跨核时间线。EvKind 始终可用，故各埋点调用处无需 cfg。

/// 事件类型（埋点种类）。始终定义（各埋点调用处引用其变体，与 diag feature 无关）。
#[derive(Clone, Copy, PartialEq, Eq)]
pub enum EvKind {
    Other,
    SyscallEnter,
    SyscallExit,
    SchedIn,
    SchedOut,
    IpiSend,
    IpiRecv,
    PageFault,
    TlbFlush,
    FrameDefer,
}

